/**
 * Izračun kalorij z MET formulo:
 *   kcal = MET × težaKg × čas_v_urah
 * Doda pribitek za vzpon: ~1 kcal/m vzpona (standardna ocena).
 */
private fun calculateCaloriesMet(
    activityType: ActivityType,
    durationSeconds: Long,
    weightKg: Double,
    elevationGainM: Float,
    avgSpeedKmh: Float
): Int {
    // 1. Omejimo nerealne hitrosti do 35 km/h za tek (GPS skoki)
    val safeSpeed = avgSpeedKmh.coerceIn(0f, 35f)

    // Prilagodi MET glede na hitrost z linearno interpolacijo,
    // da preprečimo stopničaste "GPS skoke" ki umetno dvignejo MET.
    val met = when (activityType) {
        ActivityType.RUN -> when {
            safeSpeed < 4f  -> safeSpeed // Linearno od 0 do 4
            safeSpeed < 8f  -> 4.0 + (safeSpeed - 4f) * 0.5 // 4 do 6
            safeSpeed < 10f -> 6.0 + (safeSpeed - 8f) * 1.0 // 6 do 8
            safeSpeed < 12f -> 8.0 + (safeSpeed - 10f) * 1.0 // 8 do 10
            safeSpeed < 14f -> 10.0 + (safeSpeed - 12f) * 0.75 // 10 do 11.5
            else            -> 11.5 + (safeSpeed - 14f) * 0.4
        }
        ActivityType.WALK -> when {
            safeSpeed < 3f -> 2.0 + (safeSpeed / 3f) * 0.5 // do 2.5
            safeSpeed < 5f -> 2.5 + (safeSpeed - 3f) * 0.5 // 2.5 do 3.5
            safeSpeed < 7f -> 3.5 + (safeSpeed - 5f) * 0.5 // 3.5 do 4.5
            else           -> 4.5 + (safeSpeed - 7f) * 0.3
        }
        ActivityType.SPRINT -> when {
            safeSpeed < 10f -> 8.0
            safeSpeed < 16f -> 8.0 + (safeSpeed - 10f) * 0.83 // 8 do 13
            safeSpeed < 20f -> 13.0 + (safeSpeed - 16f) * 0.75 // 13 do 16
            else            -> 16.0 + (safeSpeed - 20f) * 0.5
        }
        ActivityType.HIKE -> 6.0 + (elevationGainM / 100f) * 0.5 // Base 6.0 + gain
        ActivityType.CYCLING -> when {
            safeSpeed < 15f -> 4.0
            safeSpeed < 20f -> 6.0
            safeSpeed < 25f -> 8.0
            else            -> 10.0
        }
        else -> 5.0
    }.toDouble()

    // 2. Trajanje v urah
    val hours = durationSeconds / 3600.0
    // 3. Težo omejimo med 30kg in 200kg zaradi napak v profilu
    val safeWeight = weightKg.coerceIn(30.0, 200.0)

    val base = met * safeWeight * hours
    // Vzpon: ~0.8 kcal/m za povprečno težo 70 kg, skalira z dejansko težo. Omejen poskok GPS baz (max 2000m na log).
    val safeElevation = elevationGainM.coerceIn(0f, 2000f)
    val elevBonus = safeElevation * 0.8 * (safeWeight / 70.0)
    return (base + elevBonus).toInt().coerceAtLeast(0)
}

private fun calculateXP(activityType: ActivityType, distanceMeters: Double, timeSeconds: Long): Int {
    val baseFromDistance = distanceMeters / 100.0
    val baseFromTime = timeSeconds / 60.0
    val multiplier = when (activityType) {
        ActivityType.RUN, ActivityType.SPRINT -> 1.5
        ActivityType.HIKE, ActivityType.NORDIC -> 1.3
        ActivityType.WALK -> 1.0
        ActivityType.CYCLING -> 0.6
        ActivityType.SKIING, ActivityType.SNOWBOARD -> 0.5
        ActivityType.SKATING -> 1.0
    }
    return ((baseFromDistance + baseFromTime) * multiplier).toInt().coerceAtLeast(10)
}

@Composable
fun RunTrackerScreen(onBackPressed: () -> Unit, userProfile: UserProfile = UserProfile()) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    LaunchedEffect(Unit) {
        val config = Configuration.getInstance()
        config.userAgentValue = context.packageName
        config.cacheMapTileCount = 16.toShort()
        config.cacheMapTileOvershoot = 16.toShort()
    }

    // --- Tip aktivnosti ---
    var selectedActivity by remember { mutableStateOf(ActivityType.RUN) }
    var showActivityPicker by remember { mutableStateOf(false) }

    var service by remember { mutableStateOf<RunTrackingService?>(null) }
    var isBound by remember { mutableStateOf(false) }
    var isTracking by remember { mutableStateOf(false) }
    var isPaused by remember { mutableStateOf(false) }
    var locationPoints by remember { mutableStateOf<List<Location>>(emptyList()) }
    var elapsedSeconds by remember { mutableStateOf(0L) }
    var distanceMeters by remember { mutableStateOf(0.0) }
    var maxSpeed by remember { mutableStateOf(0f) }
    var avgSpeed by remember { mutableStateOf(0f) }
    var elevationGain by remember { mutableStateOf(0f) }
    var elevationLoss by remember { mutableStateOf(0f) }
    var mapView by remember { mutableStateOf<MapView?>(null) }
    var myLocationOverlay by remember { mutableStateOf<MyLocationNewOverlay?>(null) }
    var hasLocationPermission by remember { mutableStateOf(false) }
    var hasNotificationPermission by remember { mutableStateOf(true) }
    var showGpsDialog by remember { mutableStateOf(false) }
    var showDiscardDialog by remember { mutableStateOf(false) }
    var showSummary by remember { mutableStateOf(false) }
    var isSavingActivity by remember { mutableStateOf(false) }
    var routePolyline by remember { mutableStateOf<Polyline?>(null) }
    var isMapFollowingTarget by remember { mutableStateOf(true) }
    var finalDistance by remember { mutableStateOf(0.0) }
    var finalTime by remember { mutableStateOf(0L) }
    var finalMaxSpeed by remember { mutableStateOf(0f) }
    var finalAvgSpeed by remember { mutableStateOf(0f) }
    var finalElevationGain by remember { mutableStateOf(0f) }
    var finalElevationLoss by remember { mutableStateOf(0f) }
    var actualWeightKg by remember { mutableStateOf(70.0) }
    val uid = remember { com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId() }

    LaunchedEffect(uid) {
        if (uid != null) {
            try {
                Firebase.firestore.collection("users").document(uid)
                    .collection("weightLogs")
                    .orderBy("date", com.google.firebase.firestore.Query.Direction.DESCENDING)
                    .limit(1).get()
                    .addOnSuccessListener { snap ->
                        val w = snap.documents.firstOrNull()?.get("weightKg") as? Number
                        if (w != null) actualWeightKg = w.toDouble()
                    }
            } catch (_: Exception) {}
        }
    }

    val serviceConnection = remember {
        object : ServiceConnection {
            override fun onServiceConnected(name: ComponentName?, binder: IBinder?) {
                service = (binder as? RunTrackingService.LocalBinder)?.getService(); isBound = true
            }
            override fun onServiceDisconnected(name: ComponentName?) { service = null; isBound = false }
        }
    }

    LaunchedEffect(Unit) { context.bindService(Intent(context, RunTrackingService::class.java), serviceConnection, Context.BIND_AUTO_CREATE) }
    DisposableEffect(Unit) {
        onDispose {
            if (isBound) try { context.unbindService(serviceConnection) } catch (_: Exception) {}
            myLocationOverlay?.disableMyLocation(); myLocationOverlay?.disableFollowLocation(); mapView?.onDetach()
        }
    }
    LaunchedEffect(service) { service?.isTracking?.collect { isTracking = it } }
    LaunchedEffect(service) { service?.isPaused?.collect { isPaused = it } }
    LaunchedEffect(service) { service?.locationPoints?.collect { locationPoints = it } }
    LaunchedEffect(service) { service?.elapsedSeconds?.collect { elapsedSeconds = it } }
    LaunchedEffect(service) { service?.distanceMeters?.collect { distanceMeters = it } }
    LaunchedEffect(service) { service?.maxSpeed?.collect { maxSpeed = it } }
    LaunchedEffect(service) { service?.avgSpeed?.collect { avgSpeed = it } }
    LaunchedEffect(service) { service?.elevationGain?.collect { elevationGain = it } }
    LaunchedEffect(service) { service?.elevationLoss?.collect { elevationLoss = it } }

    LaunchedEffect(Unit) {
        hasLocationPermission = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED
        hasNotificationPermission = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU)
            ContextCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED else true
    }

    val locationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasLocationPermission = it }
    val notificationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasNotificationPermission = it }

    val prefs = context.getSharedPreferences("app_settings", Context.MODE_PRIVATE)
    var routeSmoothingEnabled by remember { mutableStateOf(prefs.getBoolean("route_smoothing", true)) }

    var isTopoMap by remember { mutableStateOf(prefs.getBoolean("topo_map", false)) }

    // Live kcal (prikazano med sledenjem)
    val liveCalories = remember(elapsedSeconds, avgSpeed, elevationGain, selectedActivity, actualWeightKg) {
        calculateCaloriesMet(selectedActivity, elapsedSeconds, actualWeightKg, elevationGain, avgSpeed * 3.6f)
    }

    LaunchedEffect(locationPoints) {
        mapView?.let { map ->
            routePolyline?.let { map.overlays.remove(it) }
            if (locationPoints.isNotEmpty()) {
                val polyline = Polyline(map).apply {
                    outlinePaint.color = android.graphics.Color.rgb(33, 150, 243)
                    outlinePaint.strokeWidth = 12f
                    outlinePaint.strokeCap = android.graphics.Paint.Cap.ROUND
                    outlinePaint.isAntiAlias = true
                    setPoints(locationPoints.map { GeoPoint(it.latitude, it.longitude) })
                }
                map.overlays.add(polyline); routePolyline = polyline

                if (isMapFollowingTarget) {
                    map.controller.animateTo(GeoPoint(locationPoints.last().latitude, locationPoints.last().longitude))
                }

                if (map.zoomLevelDouble < 16.0) map.controller.setZoom(17.0)
                map.invalidate()
            }
        }
    }

    val onMapTouch = {
        if (isMapFollowingTarget) isMapFollowingTarget = false
    }

    Box(Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background)) {
        // Mapa
        AndroidView(
            factory = { ctx ->
                MapView(ctx).apply {
                    setTileSource(if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK)
                    setMultiTouchControls(true); controller.setZoom(17.0)
                    val overlay = MyLocationNewOverlay(GpsMyLocationProvider(ctx), this).apply {
                        enableMyLocation(); enableFollowLocation(); setDrawAccuracyEnabled(true)
                    }
                    overlays.add(overlay); myLocationOverlay = overlay
                    controller.setCenter(GeoPoint(46.0569, 14.5058))
                    overlay.runOnFirstFix { post { overlay.myLocation?.let { controller.animateTo(it) } } }
                    mapView = this

                    setOnTouchListener { v, event ->
                        if (event.action == android.view.MotionEvent.ACTION_DOWN || event.action == android.view.MotionEvent.ACTION_MOVE) {
                            onMapTouch()
                            overlay.disableFollowLocation()
                        }
                        v.performClick()
                        false
                    }
                }
            },
            modifier = Modifier.fillMaxSize(),
            update = { map ->
                map.onResume()
                val currentSource = if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK
                if (map.tileProvider.tileSource != currentSource) {
                    map.setTileSource(currentSource)
                }

                map.overlayManager.tilesOverlay.setColorFilter(null)
            }
        )

        // Map Type Toggle (vedno na istem mestu, zgoraj desno, nad re-center)
        SmallFloatingActionButton(
            onClick = {
                isTopoMap = !isTopoMap
                prefs.edit().putBoolean("topo_map", isTopoMap).apply()
            },
            modifier = Modifier
                .align(Alignment.TopEnd)
                .padding(16.dp),
            containerColor = MaterialTheme.colorScheme.surfaceVariant,
            contentColor = MaterialTheme.colorScheme.onSurfaceVariant
        ) {
            Icon(Icons.Filled.Map, contentDescription = "Toggle Map Type")
        }

        // Re-center button (pod gumbom za tip mape)
        if (!isMapFollowingTarget) {
            SmallFloatingActionButton(
                onClick = {
                    isMapFollowingTarget = true
                    myLocationOverlay?.enableFollowLocation()
                    locationPoints.lastOrNull()?.let {
                        mapView?.controller?.animateTo(GeoPoint(it.latitude, it.longitude))
                    }
                },
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(top = 72.dp, end = 16.dp),
                containerColor = MaterialTheme.colorScheme.primary,
                contentColor = MaterialTheme.colorScheme.onPrimary
            ) {
                Icon(Icons.Filled.MyLocation, contentDescription = "Re-center map")
            }
        }

        // Stats card (levo zgoraj)
        Card(
            Modifier.align(Alignment.TopStart).padding(16.dp).fillMaxWidth(0.58f),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(12.dp)
        ) {
            Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(5.dp)) {
                IconButton(onClick = onBackPressed, modifier = Modifier.align(Alignment.Start)) {
                    Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back", tint = MaterialTheme.colorScheme.onSurface)
                }

                // Tip aktivnosti oznaka (med sledenjem — ne gumb)
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text(
                        "${selectedActivity.emoji} ${selectedActivity.label}",
                        fontSize = 13.sp,
                        fontWeight = FontWeight.SemiBold,
                        color = MaterialTheme.colorScheme.primary
                    )
                    if (isTracking) {
                        Spacer(Modifier.width(8.dp))
                        val (gpsProfile, gpsColor) = when (selectedActivity) {
                            ActivityType.SPRINT, ActivityType.RUN -> "High accuracy" to Color(0xFF4CAF50)
                            ActivityType.CYCLING, ActivityType.SKIING, ActivityType.SNOWBOARD, ActivityType.SKATING -> "Balanced" to MaterialTheme.colorScheme.tertiary
                            ActivityType.WALK, ActivityType.HIKE, ActivityType.NORDIC -> "Battery saver" to Color(0xFF9E9E9E)
                        }
                        Surface(
                            color = gpsColor.copy(alpha = 0.1f),
                            shape = RoundedCornerShape(4.dp),
                            border = androidx.compose.foundation.BorderStroke(1.dp, gpsColor.copy(alpha = 0.5f))
                        ) {
                            Text(
                                text = "GPS: $gpsProfile",
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Medium,
                                color = gpsColor,
                                modifier = Modifier.padding(horizontal = 4.dp, vertical = 2.dp)
                            )
                        }
                    }
                }

                Text("${"%.2f".format(distanceMeters / 1000.0)} km", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)
                Text(fmtTime(elapsedSeconds), fontSize = 16.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)

                if (selectedActivity.showSpeed) {
                    Text("Max: ${"%.1f".format(maxSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                    Text("Avg: ${"%.1f".format(avgSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showPace && distanceMeters > 50) {
                    val paceMin = if (avgSpeed > 0.1f) (1000.0 / (avgSpeed * 60.0)) else 0.0
                    Text("Pace: ${paceMin.toInt()}:${"%02d".format(((paceMin - paceMin.toInt()) * 60).toInt())} /km", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showElevation && (elevationGain > 0f || elevationLoss > 0f)) {
                    Text("↑ ${"%.0f".format(elevationGain)} m  ↓ ${"%.0f".format(elevationLoss)} m", fontSize = 13.sp, color = Color(0xFF4CAF50))
                }
                if (isTracking) {
                    Text(" $liveCalories kcal", fontSize = 13.sp, fontWeight = FontWeight.Medium, color = MaterialTheme.colorScheme.tertiary)
                    Text(
                        if (isPaused) "Paused" else "Tracking...",
                        fontSize = 12.sp,
                        color = if (isPaused) MaterialTheme.colorScheme.tertiary else Color(0xFF4CAF50),
                        fontWeight = FontWeight.Medium
                    )
                }
            }
        }

        // Controls card (spodaj)
        Card(
            Modifier.align(Alignment.BottomCenter).padding(16.dp).fillMaxWidth(),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(16.dp)
        ) {
            Column(Modifier.padding(horizontal = 16.dp, vertical = 12.dp)) {
                // --- Picker aktivnosti (samo ko ne sledimo) ---
                if (!isTracking && !showSummary) {
                    // Izbrani tip + gumb za spremembo
                    Row(
                        Modifier
                            .fillMaxWidth()
                            .clickable { showActivityPicker = !showActivityPicker }
                            .background(MaterialTheme.colorScheme.surfaceVariant, RoundedCornerShape(10.dp))
                            .padding(horizontal = 14.dp, vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label}",
                            fontSize = 15.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.onSurface,
                            modifier = Modifier.weight(1f)
                        )
                        Icon(Icons.Filled.ArrowDropDown, "Izberi aktivnost", tint = MaterialTheme.colorScheme.primary)
                    }

                    // Picker lista — horizontalni scroll
                    if (showActivityPicker) {
                        Spacer(Modifier.height(8.dp))
                        LazyRow(
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            contentPadding = PaddingValues(horizontal = 2.dp)
                        ) {
                            items(items = ActivityType.entries, key = { it.name }) { type ->
                                val isSelected = type == selectedActivity
                                Surface(
                                    shape = RoundedCornerShape(20.dp),
                                    color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.surfaceVariant,
                                    modifier = Modifier.clickable {
                                        selectedActivity = type
                                        showActivityPicker = false
                                    }
                                ) {
                                    Text(
                                        "${type.emoji} ${type.label}",
                                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 8.dp),
                                        fontSize = 13.sp,
                                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                        color = if (isSelected) Color.White else MaterialTheme.colorScheme.onSurface
                                    )
                                }
                            }
                        }
                        Spacer(Modifier.height(8.dp))
                    }
                    Spacer(Modifier.height(8.dp))
                }

                // Gumbi
                Row(
                    Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    when {
                        !isTracking && !showSummary -> Button(
                            onClick = {
                                when {
                                    !hasLocationPermission -> locationPermissionLauncher.launch(Manifest.permission.ACCESS_FINE_LOCATION)
                                    !hasNotificationPermission && Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU ->
                                        notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                                    else -> {
                                        val locationManager = context.getSystemService(Context.LOCATION_SERVICE) as LocationManager
                                        if (!locationManager.isProviderEnabled(LocationManager.GPS_PROVIDER)) {
                                            showGpsDialog = true
                                        } else {
                                            showActivityPicker = false
                                            context.startForegroundService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_START })
                                        }
                                    }
                                }
                            },
                            modifier = Modifier.weight(1f).height(56.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4CAF50)),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Icon(Icons.Filled.PlayArrow, null)
                            Spacer(Modifier.width(8.dp))
                            Text("Start ${selectedActivity.label}", fontSize = 16.sp, fontWeight = FontWeight.Bold)
                        }

                        isTracking -> {
                            Button(
                                onClick = { context.startService(Intent(context, RunTrackingService::class.java).apply { action = if (isPaused) RunTrackingService.ACTION_RESUME else RunTrackingService.ACTION_PAUSE }) },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = if (isPaused) Color(0xFF4CAF50) else MaterialTheme.colorScheme.tertiary),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(if (isPaused) Icons.Filled.PlayArrow else Icons.Filled.Pause, null); Spacer(Modifier.width(8.dp)); Text(if (isPaused) "Resume" else "Pause", fontSize = 16.sp, fontWeight = FontWeight.Bold) }

                            Button(
                                onClick = {
                                    if (distanceMeters < 20.0) {
                                        context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_PAUSE })
                                        showDiscardDialog = true
                                        return@Button
                                    }

                                    finalDistance = distanceMeters; finalTime = elapsedSeconds
                                    finalMaxSpeed = maxSpeed; finalAvgSpeed = avgSpeed
                                    finalElevationGain = elevationGain; finalElevationLoss = elevationLoss

                                    // ADDED: Samodejni predlog aktivnosti na podlagi hitrosti
                                    val currentAvgKmh = avgSpeed * 3.6f
                                    if (finalDistance > 100 && currentAvgKmh > 0) {
                                        if (selectedActivity == ActivityType.RUN && currentAvgKmh < 6.0f) {
                                            selectedActivity = ActivityType.WALK
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Walk based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        } else if (selectedActivity == ActivityType.WALK && currentAvgKmh > 7.5f) {
                                            selectedActivity = ActivityType.RUN
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Run based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        }
                                    }

                                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })

                                    showSummary = true
                                },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFF44336)),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(Icons.Filled.Stop, null); Spacer(Modifier.width(8.dp)); Text("Stop", fontSize = 16.sp, fontWeight = FontWeight.Bold) }
                        }

                        showSummary -> Spacer(Modifier.height(56.dp))
                    }
                }
            }
        }

        // Summary overlay
        if (showSummary) {
            val xpEarned = calculateXP(selectedActivity, finalDistance, finalTime)

            Box(Modifier.fillMaxSize().background(Color.Black.copy(alpha = 0.6f))) {
                Card(
                    Modifier.align(Alignment.Center).fillMaxWidth(0.88f),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                    shape = RoundedCornerShape(20.dp)
                ) {
                    Column(
                        Modifier.padding(24.dp).fillMaxWidth(),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label} Complete!",
                            fontSize = 22.sp, fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.primary
                        )
                        HorizontalDivider()

                        SummaryRow(" Distance", "${"%.2f".format(finalDistance / 1000.0)} km")
                        SummaryRow("⏱️ Duration", fmtTime(finalTime))

                        if (selectedActivity.showSpeed) {
                            SummaryRow("⚡ Max speed", "${"%.1f".format(finalMaxSpeed * 3.6)} km/h")
                            SummaryRow(" Avg speed", "${"%.1f".format(finalAvgSpeed * 3.6)} km/h")
                        }
                        if (selectedActivity.showPace && finalDistance > 50) {
                            val p = (finalTime / 60.0) / (finalDistance / 1000.0)
                            SummaryRow(" Pace", "${p.toInt()}:${"%02d".format(((p - p.toInt()) * 60).toInt())} /km")
                        }
                        if (selectedActivity.showElevation && (finalElevationGain > 0f || finalElevationLoss > 0f)) {
                            SummaryRow("⛰️ Ascent", "${"%.0f".format(finalElevationGain)} m")
                            SummaryRow("↘️ Descent", "${"%.0f".format(finalElevationLoss)} m")
                        }

                        SummaryRow(" XP Earned", "$xpEarned XP", highlight = true)

                        HorizontalDivider()
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Checkbox(
                                checked = routeSmoothingEnabled,
                                onCheckedChange = {
                                    routeSmoothingEnabled = it
                                    prefs.edit().putBoolean("route_smoothing", it).apply()
                                }
                            )
                            Text("Route smoothing (Snap-to-road)", fontSize = 14.sp)
                        }

                        Button(
                            onClick = {
                                if (isSavingActivity) return@Button
                                isSavingActivity = true
                                val sessionId = java.util.UUID.randomUUID().toString()
                                val avgKmh = finalAvgSpeed * 3.6f
                                val calories = calculateCaloriesMet(selectedActivity, finalTime, actualWeightKg, finalElevationGain, avgKmh)

                                scope.launch(Dispatchers.IO) {
                                    val mappedLocationPoints = locationPoints.map { loc ->
                                        com.example.myapplication.data.LocationPoint(
                                            latitude = loc.latitude,
                                            longitude = loc.longitude,
                                            altitude = loc.altitude,
                                            speed = loc.speed,
                                            accuracy = loc.accuracy,
                                            timestamp = loc.time
                                        )
                                    }

                                    var finalLocationPoints = mappedLocationPoints
                                    var successfullySmoothed = false
                                    if (routeSmoothingEnabled) {
                                        val isWalkingProfile = selectedActivity == ActivityType.RUN || selectedActivity == ActivityType.WALK || selectedActivity == ActivityType.HIKE
                                        // Opravimo glajenje poti za vgrajene tipe
                                        if (isWalkingProfile || selectedActivity == ActivityType.CYCLING || selectedActivity == ActivityType.SPRINT) {
                                            finalLocationPoints = com.example.myapplication.map.MapboxMapMatcher.matchRoute(mappedLocationPoints, isWalkingProfile)
                                            if (finalLocationPoints !== mappedLocationPoints) {
                                                successfullySmoothed = true
                                            }
                                        }
                                    }

                                    if (uid != null) {
                                        val avgSpeedMps = if (finalTime > 0) (finalDistance / finalTime).toFloat() else 0f
                                        val runMap = hashMapOf<String, Any>(
                                            "id" to sessionId, "userId" to uid,
                                            "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                            "endTime" to System.currentTimeMillis(),
                                            "durationSeconds" to finalTime.toInt(),
                                            "distanceMeters" to finalDistance,
                                            "maxSpeedMps" to finalMaxSpeed,
                                            "avgSpeedMps" to avgSpeedMps,
                                            "caloriesKcal" to calories,
                                            "elevationGainM" to finalElevationGain,
                                            "elevationLossM" to finalElevationLoss,
                                            "activityType" to selectedActivity.name,
                                            "createdAt" to System.currentTimeMillis(),
                                            "polylinePoints" to emptyList<Any>(),
                                            "isSmoothed" to successfullySmoothed
                                        )
                                        Firebase.firestore
                                            .collection("users").document(uid)
                                            .collection("runSessions").document(sessionId)
                                            .set(runMap)

                                        val email = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                        if (email != null) {
                                            val shareActSnap = Firebase.firestore.collection("users").document(uid).get().await()
                                            val shareAct = shareActSnap.getBoolean("share_activities") ?: false
                                            if (shareAct && finalLocationPoints.isNotEmpty()) {
                                                val rawPts = finalLocationPoints.map { Pair(it.latitude, it.longitude) }
                                                val compressed = com.example.myapplication.utils.RouteCompressor.compress(rawPts)
                                                val routeList = compressed.map { (lat, lng) -> mapOf("lat" to lat, "lng" to lng) }
                                                val pubMap = hashMapOf<String, Any>(
                                                    "activityType" to selectedActivity.name,
                                                    "distanceMeters" to finalDistance,
                                                    "elevationGainM" to finalElevationGain,
                                                    "elevationLossM" to finalElevationLoss,
                                                    "avgSpeedMps" to avgSpeedMps,
                                                    "maxSpeedMps" to finalMaxSpeed,
                                                    "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                                    "routePoints" to routeList
                                                )
                                                Firebase.firestore
                                                    .collection("users").document(uid)
                                                    .collection("publicActivities").document(sessionId)
                                                    .set(pubMap)
                                            }
                                        }
                                    }

                                    // VEDNO shranimo originalne (raw) točke, da ohranimo pravilen hitrostni graf in meritve!
                                    if (mappedLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId, mappedLocationPoints)
                                    }
                                    // Če je glajenje uspelo, shranimo dodaten file samo za risanje čudovite poti na mapi
                                    if (successfullySmoothed && finalLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId + "_smoothed", finalLocationPoints)
                                    }

                                    val xp = calculateXP(selectedActivity, finalDistance, finalTime)
                                    val runEmail = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                    if (runEmail != null) {
                                        com.example.myapplication.persistence.AchievementStore.awardXP(
                                            context, runEmail, xp,
                                            com.example.myapplication.data.XPSource.RUN_COMPLETED,
                                            "Completed ${selectedActivity.label}: ${finalDistance.toInt()}m"
                                        )

                                        val app = context.applicationContext as android.app.Application
                                        val bodyVm = androidx.lifecycle.ViewModelProvider.AndroidViewModelFactory.getInstance(app)
                                            .create(com.example.myapplication.viewmodels.BodyModuleHomeViewModel::class.java)
                                        val uiState = bodyVm.ui.value
                                        val currentDay = uiState.planDay
                                        if (!uiState.isWorkoutDoneToday && !uiState.todayIsRest && finalDistance > 1000) {
                                            bodyVm.completeWorkoutSession(
                                                isExtraWorkout = false,
                                                totalKcal = calories,
                                                totalTimeMin = finalTime / 60.0
                                            )
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "Workout Day $currentDay Complete! +$xp XP!")
                                            }
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "+$xp XP!")
                                            }
                                        }
                                    }
                                    withContext(Dispatchers.Main) {
                                        showSummary = false; onBackPressed()
                                    }
                                }
                            },
                            modifier = Modifier.fillMaxWidth(0.8f).height(50.dp),
                            enabled = !isSavingActivity,
                            colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            if (isSavingActivity) {
                                CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary)
                            } else {
                                Text("Done", fontSize = 18.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
        }
    }

    if (showGpsDialog) {
        AlertDialog(
            onDismissRequest = { showGpsDialog = false },
            title = { Text("GPS ni vklopljen", fontWeight = FontWeight.Bold) },
            text = { Text("Za sledenje aktivnosti potrebuješ vklopljeno lokacijo (GPS). Prosimo vklopi lokacijo v nastavitvah naprave.") },
            confirmButton = {
                TextButton(onClick = {
                    showGpsDialog = false
                    context.startActivity(Intent(Settings.ACTION_LOCATION_SOURCE_SETTINGS))
                }) { Text("Odpri nastavitve") }
            },
            dismissButton = { TextButton(onClick = { showGpsDialog = false }) { Text("Prekliči") } }
        )
    }

    if (showDiscardDialog) {
        AlertDialog(
            onDismissRequest = { showDiscardDialog = false },
            title = { Text("Activity Too Short", fontWeight = FontWeight.Bold) },
            text = { Text("You have recorded less than 20m. Your activity will not be saved if you finish now. Do you want to discard it?") },
            confirmButton = {
                TextButton(onClick = {
                    showDiscardDialog = false
                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })
                    onBackPressed()
                }) { Text("Discard", color = MaterialTheme.colorScheme.error) }
            },
            dismissButton = {
                TextButton(onClick = { showDiscardDialog = false }) { Text("Cancel") }
            }
        )
    }
}

@Composable
private fun SummaryRow(label: String, value: String, highlight: Boolean = false) {
    Row(
        Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(label, fontSize = 15.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
        Text(
            value,
            fontSize = if (highlight) 17.sp else 15.sp,
            fontWeight = if (highlight) FontWeight.Bold else FontWeight.Medium,
            color = if (highlight) MaterialTheme.colorScheme.tertiary else MaterialTheme.colorScheme.onSurface
        )
    }
}

private fun fmtTime(s: Long) = if (s >= 3600) "%d:%02d:%02d".format(s / 3600, (s % 3600) / 60, s % 60) else "%02d:%02d".format(s / 60, s % 60)

@file:Suppress("DEPRECATION") // Suppress deprecation warnings for GoogleSignIn usage until migration to Credential Manager

package com.example.myapplication

// =====================================================================
// MainActivity.kt
// Vsebuje: samo MainActivity class (onCreate, auth, app state, navigacija).
// Screen sealed class → AppNavigation.kt
// Drawer / Header     → AppDrawer.kt
// =====================================================================

import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.BackHandler
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.compose.setContent
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.runtime.derivedStateOf
import androidx.compose.runtime.rememberCoroutineScope
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.compose.material3.DrawerValue
import androidx.compose.material3.rememberDrawerState
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.myapplication.data.settings.UserProfileManager
import com.example.myapplication.network.OpenFoodFactsProduct
import com.example.myapplication.persistence.PlanDataStore
import com.example.myapplication.ui.home.CommunityScreen
import com.example.myapplication.ui.screens.*
import com.example.myapplication.data.PlanResult
import com.example.myapplication.ui.theme.MyApplicationTheme
import com.example.myapplication.utils.HapticFeedback
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.firebase.auth.GoogleAuthProvider
import com.google.firebase.auth.ktx.auth
import com.google.firebase.ktx.Firebase
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import kotlinx.coroutines.tasks.await


class MainActivity : ComponentActivity() {
    private lateinit var googleSignInClient: GoogleSignInClient

    // Store intent extras to trigger effects
    private val intentExtras = mutableStateOf<Bundle?>(null)

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        intentExtras.value = intent.extras
    }

    override fun onPause() {
        super.onPause()
        try {
            com.example.myapplication.worker.DailySyncWorker.schedule(this)
        } catch (_: Exception) {}
    }

    private var isSubscribed = false
    private var paymentStatus: String? = null

    // Performance timer
    private var coldStartEpochMs: Long = 0L

    // Push notification permission launcher
    private val requestNotificationPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { isGranted: Boolean ->
            Log.d("MainActivity", "Notification permission granted: $isGranted")
        }

    @Suppress("DEPRECATION")
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        coldStartEpochMs = android.os.SystemClock.elapsedRealtime()
        super.onCreate(savedInstanceState)

        // Eager load AdvancedExerciseRepository in background immediately upon app startup
        kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
            val jsonString = applicationContext.assets.open("exercises.json").bufferedReader().use { it.readText() }
            com.example.myapplication.data.AdvancedExerciseRepository.init(jsonString)
        }

        intentExtras.value = intent.extras

        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(getString(R.string.default_web_client_id))
            .requestEmail()
            .build()
        googleSignInClient = GoogleSignIn.getClient(this, gso)

        setContent {
            // First paint measurement
            LaunchedEffect(Unit) {
                val timeToPaint = android.os.SystemClock.elapsedRealtime() - coldStartEpochMs
                Log.i("AppPerf", " First paint arrived at: $timeToPaint ms")
            }

            val context = LocalContext.current
            val bodyOverviewViewModel: BodyOverviewViewmodel =
                viewModel(factory = MyViewModelFactory())
            val plans: List<com.example.myapplication.data.PlanResult> by bodyOverviewViewModel.plans.collectAsState()

            val appViewModel: AppViewModel = viewModel()
            val userProfile by appViewModel.userProfile.collectAsState()

            val networkObserver = remember { com.example.myapplication.utils.NetworkObserver(context) }
            val isOnline by networkObserver.observe().collectAsState(initial = true)

            val navViewModel: NavigationViewModel = viewModel()
            val currentScreen by navViewModel.currentScreen.collectAsState()
            val previousScreen by navViewModel.previousScreen.collectAsState()

            var isCheckingAuth by remember { mutableStateOf(true) }

            // ----- Auth stanje -----
            var isLoggedIn by remember { mutableStateOf(false) }
            var userEmail by remember { mutableStateOf("") }
            var errorMessage by remember { mutableStateOf<String?>(null) }
            var isDarkMode by remember { mutableStateOf(false) }

            // ----- Vadba stanje -----
            var selectedPlan by remember { mutableStateOf<PlanResult?>(null) }
            var isExtraWorkoutSession by remember { mutableStateOf(false) }
            var extraFocusAreas by remember { mutableStateOf<List<String>>(emptyList()) }
            var extraEquipment by remember { mutableStateOf<Set<String>>(emptySet()) }

            // ----- Prehrana stanje -----
            var scannedProduct by remember { mutableStateOf<Pair<OpenFoodFactsProduct, String>?>(null) }
            val nutritionSnackbarHostState = remember { SnackbarHostState() }

            // ----- Badge animacija -----
            var unlockedBadge by remember { mutableStateOf<com.example.myapplication.data.Badge?>(null) }

            val scope = rememberCoroutineScope()
            val drawerState = rememberDrawerState(DrawerValue.Closed)

            var pendingNavigateToNutrition by remember { mutableStateOf(false) }
            var pendingOpenBarcodeScan by remember { mutableStateOf(false) }
            var pendingOpenFoodSearch by remember { mutableStateOf(false) }

            val googleSignInLauncher = rememberLauncherForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
                val task = GoogleSignIn.getSignedInAccountFromIntent(result.data)
                try {
                    val account = task.getResult(com.google.android.gms.common.api.ApiException::class.java)
                    firebaseAuthWithGoogle(account, onSuccess = {
                        val user = Firebase.auth.currentUser
                        if (user != null && user.email != null) {
                            isLoggedIn = true; userEmail = user.email!!
                            appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                            scope.launch { isDarkMode = UserProfileManager.isDarkMode(userEmail) }
                            navViewModel.clearStack(); navViewModel.navigateTo(Screen.Dashboard)
                        } else errorMessage = "Google sign-in error."
                    }, onError = { err -> errorMessage = err })
                } catch (e: Exception) { errorMessage = "Google sign-in failed: ${e.localizedMessage}" }
            }

            // === INITIAL AUTH & SYNC FLOW ===
            LaunchedEffect(Unit) {
                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                val accountEmail = com.google.firebase.ktx.Firebase.auth.currentUser?.email

                // Preveri fresh_start flag (nastavljen ob delete data/account)
                val appFlags = context.getSharedPreferences("app_flags", Context.MODE_PRIVATE)
                if (appFlags.getBoolean("fresh_start_on_login", false)) {
                    // Pobriši vse bm_prefs na čisto — novo začetno stanje
                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                        .edit().clear().apply()
                    context.getSharedPreferences("algorithm_prefs", Context.MODE_PRIVATE)
                        .edit().clear().apply()
                    // Počisti flag
                    appFlags.edit().remove("fresh_start_on_login").apply()
                    Log.d("MainActivity", "✅ Fresh start: bm_prefs reset")
                }

                // ── Faza 5: One-time migracija — pobriši stare lokalne SharedPrefs caches ──
                // water_cache, burned_cache, calories_cache, food_cache so bili legaccy
                // vmesni buffer za sync. Firestore SDK (isPersistenceEnabled=true) zdaj
                // skrbi za offline delovanje sam — te datoteke niso več potrebne.
                val migPrefs = context.getSharedPreferences("migration_flags", Context.MODE_PRIVATE)
                if (!migPrefs.getBoolean("faza5_legacy_purge_done", false)) {
                    com.example.myapplication.persistence.DailySyncManager.clearLegacyCache(context)
                    migPrefs.edit().putBoolean("faza5_legacy_purge_done", true).apply()
                    Log.i("MainActivity", "✅ Faza 5: Legacy lokalni cache počiščen → Firestore je Single Source of Truth")
                }
                // ──────────────────────────────────────────────────────────────────────────

                    if (accountEmail != null) {
                        userEmail = accountEmail

                        // Nastavi uporabniški profil
                        appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                        isDarkMode = UserProfileManager.isDarkMode(userEmail)

                    // Preveri in sinhroniziraj badge ob zagonu
                    try {
                        val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                        useCase.checkAndSyncBadgesOnStartup()
                    }
                    catch (e: Exception) { Log.e("MainActivity", "Badge sync error: ${e.message}") }

                    // Sinhronizacija načrtov
                    try { PlanDataStore.migrateLocalPlansToFirestore(context) } catch (_: Exception) {}
                    bodyOverviewViewModel.refreshPlans()

                    // Osveži podatke o profilu iz Firestore
                    kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
                        try {
                            val remote = UserProfileManager.loadProfileFromFirestore(userEmail)
                            if (remote != null) {
                                UserProfileManager.saveProfile(remote)
                                val actParsed = remote.activityLevel?.replace("x", "")?.toIntOrNull()
                                if (actParsed != null && actParsed > 0) {
                                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        .edit().putInt("weekly_target", actParsed).apply()
                                }
                                withContext(Dispatchers.Main) { appViewModel.handleIntent(AppIntent.SetProfile(remote)) }
                            }
                        } catch (_: Exception) {}
                    }

                    // Nastavitev start poslušanja s pomočjo UseCase
                    appViewModel.handleIntent(AppIntent.StartListening(userEmail))
                }
                isCheckingAuth = false
            }

            // ----- Auth check ob zagonu -----
            LaunchedEffect(Unit) {
                val user = Firebase.auth.currentUser
                if (user != null && (user.isEmailVerified || user.providerData.any { it.providerId == "google.com" })) {
                    isLoggedIn = true
                    userEmail = user.email ?: ""

                    appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                    isDarkMode = UserProfileManager.isDarkMode(userEmail)
                    navViewModel.navigateTo(if (pendingNavigateToNutrition) Screen.Nutrition else Screen.Dashboard)

                    scope.launch(Dispatchers.IO) {
                        try {
                            val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                            useCase.recordLoginOnly()
                        }
                        catch (e: Exception) { Log.e("MainActivity", "Login streak error: ${e.message}") }
                    }
                    scope.launch(Dispatchers.IO) {
                        try {
                            val profile = UserProfileManager.loadProfile(userEmail)
                            com.example.myapplication.workers.WeeklyStreakWorker.ensureScheduled(context, profile.startOfWeek)
                        } catch (e: Exception) { Log.e("MainActivity", "WeeklyStreakWorker error: ${e.message}") }
                    }

                    // Tedenski čistilec starih GPS run_routes .json datotek
                    try {
                        com.example.myapplication.worker.RunRouteCleanupWorker.ensureScheduled(context)
                    } catch (e: Exception) { Log.e("MainActivity", "RunRouteCleanupWorker error: ${e.message}") }

                    delay(250)
                    scope.launch(Dispatchers.IO) {
                        try {
                            val remote = UserProfileManager.loadProfileFromFirestore(userEmail)
                            if (remote != null) {
                                UserProfileManager.saveProfile(remote)
                                val actParsed = remote.activityLevel?.replace("x", "")?.toIntOrNull()
                                if (actParsed != null && actParsed > 0) {
                                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        .edit().putInt("weekly_target", actParsed).apply()
                                }
                                withContext(Dispatchers.Main) { appViewModel.handleIntent(AppIntent.SetProfile(remote)) }
                            }
                        } catch (_: Exception) {}
                    }
                    scope.launch(Dispatchers.IO) {
                        delay(1500)
                        try {
                            val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                            useCase.checkAndSyncBadgesOnStartup()
                        }
                        catch (e: Exception) { Log.e("MainActivity", "Badge sync error: ${e.message}") }
                    }
                    scope.launch {
                        try { PlanDataStore.migrateLocalPlansToFirestore(context) } catch (_: Exception) {}
                        bodyOverviewViewModel.refreshPlans()
                        try { com.example.myapplication.widget.StreakWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                        try { com.example.myapplication.widget.PlanDayWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                        val syncUid = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId()
                        if (syncUid != null) {
                            try { com.example.myapplication.persistence.DailySyncManager.syncOnAppOpen(context, syncUid) } catch (_: Exception) {}
                        }
                    }

                    // Real-time Firestore listener — kliče loadProfileFromFirestore() (ni ročnega gradnje UserProfile)
                    appViewModel.handleIntent(AppIntent.StartListening(userEmail))
                } else {
                    navViewModel.navigateTo(Screen.Index)
                }
                isCheckingAuth = false
            }

            // ----- Workers scheduling ob loginu (email, Google, auto-login) -----
            LaunchedEffect(isLoggedIn) {
                if (isLoggedIn) {
                    try {
                        com.example.myapplication.workers.StreakReminderWorker.createNotificationChannel(context)
                        com.example.myapplication.workers.StreakReminderWorker.scheduleForToday(context)
                    } catch (e: Exception) { Log.e("MainActivity", "StreakReminderWorker schedule error: ${e.message}") }
                }
            }

            // ----- Widget intent handling -----
            var showWeightInputDialog by remember { mutableStateOf(false) }
            var openBarcodeScan by remember { mutableStateOf(false) }
            var openFoodSearch by remember { mutableStateOf(false) }
            var pendingNavigateToBodyModule by remember { mutableStateOf(false) }

            LaunchedEffect(intentExtras.value) {
                val extras = intentExtras.value ?: return@LaunchedEffect
                Log.d("MainActivity", "Intent extras: NAVIGATE_TO=${extras.getString("NAVIGATE_TO")}")
                if (extras.getBoolean("OPEN_WEIGHT_INPUT", false)) {
                    showWeightInputDialog = true
                    if (isLoggedIn) navViewModel.navigateTo(Screen.Progress)
                }
                if (extras.getString("NAVIGATE_TO") == "nutrition") {
                    val wantsScan = extras.getBoolean("OPEN_BARCODE_SCAN", false)
                    val wantsSearch = extras.getBoolean("OPEN_FOOD_SEARCH", false)
                    if (isLoggedIn && !isCheckingAuth) {
                        navViewModel.navigateTo(Screen.Nutrition)
                        delay(150)
                        if (wantsScan) openBarcodeScan = true
                        if (wantsSearch) openFoodSearch = true
                    } else {
                        pendingNavigateToNutrition = true
                        pendingOpenBarcodeScan = wantsScan
                        pendingOpenFoodSearch = wantsSearch
                    }
                }
                if (extras.getString("NAVIGATE_TO") == "body_module") {
                    if (isLoggedIn && !isCheckingAuth) {
                        navViewModel.navigateTo(Screen.BodyModuleHome)
                    } else {
                        pendingNavigateToBodyModule = true
                    }
                }
            }

            LaunchedEffect(isCheckingAuth, isLoggedIn, pendingNavigateToBodyModule) {
                if (!isCheckingAuth && isLoggedIn && pendingNavigateToBodyModule) {
                    navViewModel.navigateTo(Screen.BodyModuleHome)
                    pendingNavigateToBodyModule = false
                }
            }

            LaunchedEffect(isCheckingAuth, isLoggedIn, pendingNavigateToNutrition, pendingOpenBarcodeScan, pendingOpenFoodSearch) {
                if (!isCheckingAuth && isLoggedIn && pendingNavigateToNutrition) {
                    navViewModel.navigateTo(Screen.Nutrition)
                    delay(150)
                    if (pendingOpenBarcodeScan) openBarcodeScan = true
                    if (pendingOpenFoodSearch) openFoodSearch = true
                    pendingNavigateToNutrition = false; pendingOpenBarcodeScan = false; pendingOpenFoodSearch = false
                }
            }

            // ----- Navigacijski pomočniki -----
            fun navigateTo(screen: Screen) = navViewModel.navigateTo(screen)

            fun navigateBack() = navViewModel.navigateBack(
                isLoggedIn = isLoggedIn,
                hasSelectedPlan = selectedPlan != null,
                onClearSelectedPlan = { selectedPlan = null },
                onClearError = { errorMessage = null },
                onFinish = { finish() }
            )

            BackHandler { navigateBack() }

            val shouldUseDarkMode = if (!isLoggedIn && currentScreen is Screen.Index) true else isDarkMode

            MyApplicationTheme(darkTheme = shouldUseDarkMode) {
                if (isCheckingAuth) {
                    Box(
                        modifier = Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background),
                        contentAlignment = Alignment.Center
                    ) { CircularProgressIndicator(color = MaterialTheme.colorScheme.tertiary) }
                } else if (isLoggedIn) {
                    val enableDrawerGestures = when (currentScreen) {
                        is Screen.Dashboard, is Screen.Progress, is Screen.BodyModuleHome,
                        is Screen.BodyOverview, is Screen.MyPlans, is Screen.FaceModule,
                        is Screen.HairModule, is Screen.Shop,
                        is Screen.Community, is Screen.MyAccount, is Screen.ExerciseHistory,
                        is Screen.ManualExerciseLog, is Screen.Nutrition -> true
                        else -> currentScreen !is Screen.RunTracker && currentScreen !is Screen.ActivityLog
                    }

                    ModalNavigationDrawer(
                        drawerState = drawerState,
                        gesturesEnabled = enableDrawerGestures,
                        drawerContent = {
                            FigmaDrawerContent(
                                userProfile = userProfile,
                                onClose = { scope.launch { drawerState.close() } },
                                onLogout = {
                                    com.google.firebase.ktx.Firebase.auth.signOut()
                                    googleSignInClient.signOut()
                                    com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                    appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                    val lp = context.getSharedPreferences("local_prefs", Context.MODE_PRIVATE)
                                    lp.edit().putString("fcm_token", "").apply()
                                    isLoggedIn = false
                                    navViewModel.clearStack()
                                },
                                                onProfileUpdate = { updatedProfile ->
                                                    appViewModel.handleIntent(AppIntent.SetProfile(updatedProfile))
                                                    UserProfileManager.saveProfile(updatedProfile)
                                                    scope.launch { UserProfileManager.saveProfileFirestore(updatedProfile) }
                                                },
                                                isDarkMode = isDarkMode,
                                onDarkModeToggle = {
                                    isDarkMode = !isDarkMode
                                    scope.launch { UserProfileManager.setDarkMode(userEmail, isDarkMode) }
                                },
                                onNavigateToPrivacyPolicy = { navigateTo(Screen.PrivacyPolicy); scope.launch { drawerState.close() } },
                                onNavigateToTermsOfService = { navigateTo(Screen.TermsOfService); scope.launch { drawerState.close() } },
                                onNavigateToContact = { navigateTo(Screen.Contact); scope.launch { drawerState.close() } },
                                onNavigateToAbout = { navigateTo(Screen.About); scope.launch { drawerState.close() } },
                                onNavigateToAchievements = { navigateTo(Screen.Achievements); scope.launch { drawerState.close() } },
                                onNavigateToBadges = { navigateTo(Screen.Achievements); scope.launch { drawerState.close() } },
                                onNavigateToHealthConnect = { navigateTo(Screen.HealthConnect); scope.launch { drawerState.close() } },
                                onNavigateToDebugDashboard = { navigateTo(Screen.DebugDashboard); scope.launch { drawerState.close() } },
                                onNavigateToMyAccount = { navigateTo(Screen.MyAccount); scope.launch { drawerState.close() } }
                            )
                        }
                    ) {
                        val showBottomBar by remember {
                            derivedStateOf {
                                isLoggedIn && selectedPlan == null && when (currentScreen) {
                                    is Screen.Dashboard, is Screen.Progress, is Screen.BodyOverview,
                                    is Screen.MyPlans, is Screen.BodyModuleHome, is Screen.Nutrition,
                                    is Screen.Community, is Screen.MyAccount, is Screen.FaceModule,
                                    is Screen.HairModule, is Screen.Shop -> true
                                    else -> false
                                }
                            }
                        }

                        Scaffold(
                            topBar = {
                                if (currentScreen is Screen.Dashboard) {
                                    GlobalHeaderBar(
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        }
                                    )
                                }
                            },
                            snackbarHost = {
                                SnackbarHost(
                                    hostState = nutritionSnackbarHostState,
                                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 12.dp)
                                ) { data ->
                                    Surface(
                                        color = MaterialTheme.colorScheme.surface,
                                        contentColor = MaterialTheme.colorScheme.onSurface,
                                        shape = RoundedCornerShape(20.dp),
                                        tonalElevation = 6.dp, shadowElevation = 8.dp,
                                        modifier = Modifier.fillMaxWidth()
                                    ) {
                                        Row(modifier = Modifier.padding(horizontal = 18.dp, vertical = 12.dp), verticalAlignment = Alignment.CenterVertically) {
                                            Text(data.visuals.message, style = MaterialTheme.typography.bodyMedium)
                                        }
                                    }
                                }
                            },
                            bottomBar = {
                                if (showBottomBar) {
                                    AppBottomBar(currentScreen = currentScreen, onSelect = { target ->
                                        selectedPlan = null; navigateTo(target)
                                    })
                                }
                            },
                            containerColor = MaterialTheme.colorScheme.background
                        ) { innerPadding ->
                            val shouldApplyPadding = currentScreen !is Screen.Progress && currentScreen !is Screen.Nutrition && currentScreen !is Screen.Community
                            Box(modifier = Modifier.fillMaxSize().then(if (shouldApplyPadding) Modifier.padding(innerPadding) else Modifier)) {
                                // ============================================================
                                // SCREEN ROUTING — vsak zaslon ima svojo vrstico
                                // Za dodajanje novega zaslona: dodaj Screen objekt v AppNavigation.kt
                                // in dodaj when blok tukaj.
                                // ============================================================
                                when {
                                    currentScreen is Screen.LoadingWorkout -> LoadingWorkoutScreen(
                                        onLoadingComplete = {
                                            scope.launch {
                                                isExtraWorkoutSession = false
                                                // replaceTo() namesto navigateTo() — LoadingWorkout NE gre v back-stack,
                                                // Back iz WorkoutSession gre direktno na BodyModuleHome (popTo).
                                                navViewModel.replaceTo(Screen.WorkoutSession)
                                            }
                                        }
                                    )
                                    currentScreen is Screen.BodyModuleHome -> BodyModuleHomeScreen(
                                        onBack = { navigateBack() },
                                        onStartPlan = { navigateTo(Screen.BodyOverview) },
                                        onStartWorkout = { plan ->
                                            if (plan == null) { navigateTo(Screen.BodyOverview); return@BodyModuleHomeScreen }
                                            selectedPlan = plan; navigateTo(Screen.LoadingWorkout)
                                        },
                                        onStartAdditionalWorkout = { navigateTo(Screen.GenerateWorkout) },
                                        currentPlan = plans.maxByOrNull { it.createdAt },
                                        onOpenHistory = { navigateTo(Screen.ExerciseHistory) },
                                        onOpenManualLog = { navigateTo(Screen.ManualExerciseLog) },
                                        onStartRun = { navigateTo(Screen.RunTracker) },
                                        onOpenActivityLog = { navigateTo(Screen.ActivityLog) }
                                    )
                                    currentScreen is Screen.ActivityLog -> ActivityLogScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.WorkoutSession -> {
                                        val frozenPlan = remember(currentScreen) { selectedPlan ?: plans.maxByOrNull { it.createdAt } }
                                        WorkoutSessionScreen(
                                            currentPlan = frozenPlan,
                                            isExtra = isExtraWorkoutSession,
                                            extraFocusAreas = extraFocusAreas,
                                            extraEquipment = extraEquipment,
                                            onBack = {
                                                selectedPlan = null; isExtraWorkoutSession = false
                                                extraFocusAreas = emptyList(); extraEquipment = emptySet()
                                                navViewModel.popTo(Screen.BodyModuleHome)
                                            },
                                            onFinished = {
                                                selectedPlan = null; isExtraWorkoutSession = false
                                                extraFocusAreas = emptyList(); extraEquipment = emptySet()
                                                navViewModel.popTo(Screen.BodyModuleHome)
                                                // Posodobi Plan Day widget takoj po končani vadbi
                                                try { com.example.myapplication.widget.PlanDayWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                                                try { com.example.myapplication.widget.StreakWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                                            },
                                            onXPAdded = { appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail))) },
                                            onBadgeUnlocked = { badge ->
                                                unlockedBadge = badge
                                                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                            }
                                        )
                                    }
                                    currentScreen is Screen.FaceModule -> FaceModuleScreen(
                                        onBack = { navigateBack() }
                                    )

                                    currentScreen is Screen.HairModule -> HairModuleScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Shop -> ShopScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Progress -> ProgressScreen(
                                        openWeightInput = showWeightInputDialog,
                                        userProfile = userProfile,
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        }
                                    )
                                    currentScreen is Screen.Nutrition -> {
                                        NutritionScreen(
                                            plan = plans.maxByOrNull { it.createdAt },
                                            onScanBarcode = { openBarcodeScan = false; navigateTo(Screen.BarcodeScanner) },
                                            scannedProduct = scannedProduct,
                                            onProductConsumed = { scannedProduct = null },
                                            openBarcodeScan = openBarcodeScan,
                                            openFoodSearch = openFoodSearch,
                                            onXPAdded = { appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail))) },
                                            snackbarHostState = nutritionSnackbarHostState,
                                            userProfile = userProfile,
                                            isOnline = isOnline,
                                            onOpenMenu = {
                                                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                                scope.launch { drawerState.open() }
                                            },
                                            onProClick = {
                                                errorMessage = null
                                                navViewModel.navigateTo(Screen.ProFeatures)
                                            }
                                        )
                                    }
                                    currentScreen is Screen.BarcodeScanner -> BarcodeScannerScreen(
                                        onDismiss = { navigateBack() },
                                        onProductScanned = { product, barcode -> scannedProduct = Pair(product, barcode); navigateBack() }
                                    )

                                    currentScreen is Screen.ExerciseHistory -> ExerciseHistoryScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.ManualExerciseLog -> ManualExerciseLogScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.RunTracker -> RunTrackerScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.GenerateWorkout -> GenerateWorkoutScreen(
                                        onBack = { navigateBack() },
                                        currentPlan = plans.maxByOrNull { it.createdAt },
                                        onSelectWorkout = { generatedWorkout ->
                                            val latestPlan = plans.maxByOrNull { it.createdAt }
                                            if (latestPlan != null) {
                                                isExtraWorkoutSession = true
                                                extraFocusAreas = generatedWorkout.focus.split(",").map { it.trim() }.filter { it.isNotBlank() }
                                                extraEquipment = generatedWorkout.equipment.ifEmpty { setOf("bodyweight") }
                                                selectedPlan = latestPlan
                                                navigateTo(Screen.WorkoutSession)
                                            } else navigateTo(Screen.BodyOverview)
                                        }
                                    )
                                    currentScreen is Screen.Community -> CommunityScreen(
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        },
                                        onViewProfile = { userId -> navigateTo(Screen.PublicProfile(userId)) }
                                    )
                                    currentScreen is Screen.BodyOverview -> BodyOverviewScreen(
                                        plans = plans,
                                        onCreateNewPlan = { navigateTo(Screen.BodyModule) },
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.Dashboard -> {
                                        com.example.myapplication.ui.screens.DashboardScreen(
                                            userEmail = userEmail,
                                            onLogout = {
                                                com.google.firebase.ktx.Firebase.auth.signOut()
                                                googleSignInClient.signOut()
                                                com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                                appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                                isLoggedIn = false
                                                navViewModel.clearStack()
                                            },
                                            onModuleClick = { module ->
                                                when(module) {
                                                    "Body" -> navigateTo(Screen.BodyModuleHome)
                                                    "Face" -> navigateTo(Screen.FaceModule)
                                                    "Hair" -> navigateTo(Screen.HairModule)
                                                    "Shop" -> navigateTo(Screen.Shop)
                                                }
                                            },
                                            onAccountClick = { navigateTo(Screen.MyAccount) },
                                            onProClick = { navigateTo(Screen.ProFeatures) },
                                            onOpenMenu = {
                                                com.example.myapplication.utils.HapticFeedback.performHapticFeedback(context, com.example.myapplication.utils.HapticFeedback.FeedbackType.DRAWER_OPEN)
                                                scope.launch { drawerState.open() }
                                            },
                                            showLocalHeader = false
                                        )
                                    }
                                    currentScreen is Screen.ProFeatures -> ProFeaturesScreen(
                                        onFreeTrial = {},
                                        onContinue = { if (isLoggedIn) { errorMessage = null; navigateTo(Screen.ProSubscription) } },
                                        onBack = { errorMessage = null; navigateBack() },
                                        errorMessage = errorMessage
                                    )
                                    currentScreen is Screen.BodyModule -> BodyPlanQuizScreen(
                                        onBack = { navigateBack() },
                                        onQuizDataCollected = { quizData ->
                                            @Suppress("UNCHECKED_CAST")
                                            val limitationsList = quizData["limitations"] as? List<String> ?: emptyList()
                                            Log.d("MainActivity", "onQuizDataCollected: height=${quizData["height"]}")
                                            val newHeight = (quizData["height"] as? Number)?.toDouble() ?: (quizData["height"] as? String)?.toDoubleOrNull()
                                            val newAge = (quizData["age"] as? Number)?.toInt() ?: (quizData["age"] as? String)?.toIntOrNull()
                                            val newGender = quizData["gender"] as? String
                                            val updatedFromQuiz = userProfile.copy(
                                                height = newHeight, age = newAge, gender = newGender,
                                                activityLevel = quizData["frequency"] as? String,
                                                experience = quizData["experience"] as? String,
                                                bodyFat = quizData["bodyFat"] as? String,
                                                workoutGoal = quizData["goal"] as? String ?: "",
                                                limitations = limitationsList,
                                                nutritionStyle = quizData["nutrition"] as? String,
                                                sleepHours = quizData["sleep"] as? String
                                            )
                                            appViewModel.handleIntent(AppIntent.SetProfile(updatedFromQuiz))
                                            UserProfileManager.saveProfile(updatedFromQuiz)
                                            scope.launch { UserProfileManager.saveProfileFirestore(updatedFromQuiz) }

                                            val freqStr = quizData["frequency"] as? String
                                            val freqParsed = freqStr?.replace("x", "")?.replace("X", "")?.trim()?.toIntOrNull()
                                            if (freqParsed != null && freqParsed > 0) {
                                                context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                                    .edit().putInt("weekly_target", freqParsed).apply()
                                                Log.d("MainActivity", "weekly_target set from quiz: $freqParsed")
                                            }
                                        },
                                        onFinish = { plan ->
                                            scope.launch {
                                                if (plans.isNotEmpty()) plans.forEach { PlanDataStore.deletePlan(context, it.id) }
                                                PlanDataStore.addPlan(context, plan)
                                                var currentProfile = userProfile
                                                if (currentProfile.height == null || currentProfile.height == 0.0)
                                                    currentProfile = UserProfileManager.loadProfile(userEmail)
                                                val finalProfile = currentProfile.copy(equipment = plan.equipment, focusAreas = plan.focusAreas)
                                                UserProfileManager.saveProfileFirestore(finalProfile)
                                                UserProfileManager.saveProfile(finalProfile)
                                                appViewModel.handleIntent(AppIntent.SetProfile(finalProfile))
                                                val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                                                useCase.recordPlanCreation()
                                                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                                val uid = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId()
                                                if (uid != null) {
                                                    val nutritionPlan = com.example.myapplication.data.NutritionPlan(
                                                        calories = plan.calories, protein = plan.protein,
                                                        carbs = plan.carbs, fat = plan.fat,
                                                        algorithmData = plan.algorithmData,
                                                        lastUpdated = System.currentTimeMillis()
                                                    )
                                                    com.example.myapplication.persistence.NutritionPlanStore.saveNutritionPlan(uid, nutritionPlan)
                                                }
                                                val freqFromPlan = plan.trainingDays.takeIf { it > 0 }
                                                val actParsed = userProfile.activityLevel?.replace("x", "")?.replace("X", "")?.trim()?.toIntOrNull()
                                                val weeklyTargetToSave = actParsed?.takeIf { it > 0 } ?: freqFromPlan ?: 3
                                                // ✅ Global Audit (Faza 13.3): NE beremo streak/total/lastEpoch iz bm_prefs (deprecated).
                                                // Ob novem planu posodabljamo SAMO plan-specifична polja: plan_day=1, weekly_target, weekly_done=0.
                                                // streak_days ostane nespremenjen v Firestoreu — user ne izgubi streaka pri zamenjavi plana.
                                                if (userEmail.isNotBlank()) {
                                                    try {
                                                        com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocRef()
                                                            .set(
                                                                mapOf(
                                                                    "plan_day"      to 1,
                                                                    "weekly_target" to weeklyTargetToSave,
                                                                    "weekly_done"   to 0
                                                                ),
                                                                com.google.firebase.firestore.SetOptions.merge()
                                                            ).await()
                                                        android.util.Log.d("MainActivity", "✅ New plan init: plan_day=1, weekly_target=$weeklyTargetToSave (streak preserved)")
                                                    } catch (e: Exception) {
                                                        android.util.Log.e("MainActivity", "❌ New plan Firestore init failed: ${e.message}")
                                                    }
                                                }
                                                bodyOverviewViewModel.refreshPlans()
                                                navViewModel.navigateTo(Screen.BodyOverview)
                                            }
                                        }
                                    )
                                    currentScreen is Screen.ProSubscription -> ProSubscriptionScreen(
                                        onBack = { navigateBack() },
                                        onSubscribed = { navigateTo(Screen.Dashboard) }
                                    )
                                    currentScreen is Screen.MyPlans -> MyPlansScreen(
                                        plans = plans,
                                        onPlanClick = { plan -> selectedPlan = plan },
                                        onPlanDelete = { plan -> scope.launch { PlanDataStore.deletePlan(context, plan.id) } }
                                    )
                                    currentScreen is Screen.MyAccount -> MyAccountScreen(
                                        userProfile = userProfile,
                                        onNavigateToDevSettings = { navigateTo(Screen.DeveloperSettings) },
                                        onProfileUpdate = { updatedProfile ->
                                            appViewModel.handleIntent(AppIntent.SetProfile(updatedProfile))
                                            UserProfileManager.saveProfile(updatedProfile)
                                            scope.launch { UserProfileManager.saveProfileFirestore(updatedProfile) }
                                        },
                                        onDeleteAllData = {
                                            scope.launch {
                                                try {
                                                    UserProfileManager.deleteUserData(userEmail); PlanDataStore.deleteAllPlans()
                                                    PlanDataStore.clearPlan(context); UserProfileManager.clearAllLocalData()
                                                    bodyOverviewViewModel.clearPlans(); errorMessage = "All data deleted."
                                                } catch (e: Exception) { errorMessage = "Delete failed: ${e.localizedMessage}" }
                                            }
                                        },
                                        onDeleteAccount = {
                                            scope.launch {
                                                try {
                                                    UserProfileManager.deleteUserData(userEmail); PlanDataStore.deleteAllPlans()
                                                    PlanDataStore.clearPlan(context); UserProfileManager.clearAllLocalData()
                                                    com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                                    try { Firebase.auth.currentUser?.delete()?.await() }
                                                    catch (reauth: com.google.firebase.auth.FirebaseAuthRecentLoginRequiredException) {
                                                        Firebase.auth.signOut()
                                                        errorMessage = "Account data deleted. Please sign in again and retry to fully delete account."
                                                    }
                                                    bodyOverviewViewModel.clearPlans(); isLoggedIn = false; userEmail = ""
                                                    appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                                    navViewModel.clearStack(); navViewModel.navigateTo(Screen.Index)
                                                    scope.launch { drawerState.close() }
                                                } catch (e: Exception) { errorMessage = "Account deletion failed: ${e.localizedMessage}" }
                                            }
                                        },
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.DeveloperSettings -> DeveloperSettingsScreen(
                                        onBack = { navigateBack() },
                                        userProfile = userProfile,
                                        currentPlan = plans.maxByOrNull { it.createdAt }
                                    )
                                    currentScreen is Screen.DebugDashboard -> com.example.myapplication.ui.screens.DebugDashboardScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.PrivacyPolicy -> PrivacyPolicyScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.TermsOfService -> TermsOfServiceScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Contact -> ContactScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.About -> AboutScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Achievements -> {
                                        val prefs = context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        AchievementsScreen(
                                            userProfile = userProfile, activePlan = plans.firstOrNull(),
                                            currentPlanDay = prefs.getInt("plan_day", 1),
                                            weeklyDone = prefs.getInt("weekly_done", 0),
                                            onRefresh = { bodyOverviewViewModel.refreshPlans() },
                                            onBack = { navigateBack() }
                                        )
                                    }
                                    currentScreen is Screen.PublicProfile -> {
                                        val userId = (currentScreen as Screen.PublicProfile).userId
                                        var profileData by remember { mutableStateOf<com.example.myapplication.data.PublicProfile?>(null) }
                                        LaunchedEffect(userId) { profileData = com.example.myapplication.persistence.ProfileStore.getPublicProfile(userId) }
                                        profileData?.let { PublicProfileScreen(profile = it, onBack = { navigateBack() }) }
                                            ?: Box(Modifier.fillMaxSize(), Alignment.Center) { CircularProgressIndicator() }
                                    }
                                    currentScreen is Screen.HealthConnect -> HealthConnectScreen(
                                        onBack = { navigateBack() }
                                    )
                                }
                            }
                        }
                    }
                } else {
                    // Odjavljeni uporabnik
                    Scaffold(containerColor = MaterialTheme.colorScheme.background) { innerPadding ->
                        val shouldApplyPadding = currentScreen is Screen.Login
                        Box(modifier = Modifier.then(if (shouldApplyPadding) Modifier.padding(innerPadding) else Modifier)) {
                            when {
                                currentScreen is Screen.Index -> IndexScreen(
                                    onLoginClick = { errorMessage = null; navigateTo(Screen.Login(startInSignUp = false)) },
                                    onSignUpClick = { errorMessage = null; navigateTo(Screen.Login(startInSignUp = true)) },
                                    onViewProFeatures = { errorMessage = null; navigateTo(Screen.ProFeatures) }
                                )
                                currentScreen is Screen.Login -> LoginScreen(
                                    startInSignUp = (currentScreen as Screen.Login).startInSignUp,
                                    onForgotPassword = { email ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        Firebase.auth.sendPasswordResetEmail(email).addOnCompleteListener { task ->
                                            errorMessage = if (task.isSuccessful) "Password reset email sent to $email"
                                            else task.exception?.localizedMessage ?: "Failed to send reset email"
                                        }
                                    },
                                    onLogin = { email, password ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        if (password.isBlank()) { errorMessage = "Please enter your password."; return@LoginScreen }
                                        Firebase.auth.signInWithEmailAndPassword(email, password).addOnCompleteListener { task ->
                                            if (task.isSuccessful) {
                                                val user = Firebase.auth.currentUser
                                                if (user != null && user.isEmailVerified) {
                                                    isLoggedIn = true; userEmail = email
                                                    appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                                    scope.launch { isDarkMode = UserProfileManager.isDarkMode(userEmail) }
                                                    navViewModel.clearStack(); navViewModel.navigateTo(Screen.Dashboard)
                                                } else if (user != null) { errorMessage = "Please verify your email first!"; Firebase.auth.signOut() }
                                                else errorMessage = "Error: no user."
                                            } else errorMessage = task.exception?.localizedMessage ?: "Login failed."
                                        }
                                    },
                                    onSignup = { email, password, confirmPassword ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        if (password.isBlank()) { errorMessage = "Please enter your password."; return@LoginScreen }
                                        if (password != confirmPassword) { errorMessage = "Passwords do not match."; return@LoginScreen }
                                        Firebase.auth.createUserWithEmailAndPassword(email, password).addOnCompleteListener { task ->
                                            if (task.isSuccessful) {
                                                Firebase.auth.currentUser?.sendEmailVerification()
                                                errorMessage = "Sign-up successful! Check your email to verify."
                                                Firebase.auth.signOut()
                                            } else errorMessage = task.exception?.localizedMessage ?: "Sign-up failed."
                                        }
                                    },
                                    onBackToHome = { errorMessage = null; navViewModel.navigateTo(Screen.Index) },
                                    errorMessage = errorMessage,
                                    onGoogleSignInClick = { errorMessage = null; googleSignInLauncher.launch(googleSignInClient.signInIntent) },
                                    onTermsClick = { navigateTo(Screen.TermsOfService) },
                                    onPrivacyClick = { navigateTo(Screen.PrivacyPolicy) }
                                )
                                currentScreen is Screen.ProFeatures -> ProFeaturesScreen(
                                    onFreeTrial = {},
                                    onContinue = { errorMessage = null; navigateTo(Screen.Login()) },
                                    onBack = { errorMessage = null; navigateBack() },
                                    errorMessage = errorMessage
                                )
                                currentScreen is Screen.TermsOfService -> TermsOfServiceScreen(onBack = { navigateBack() })
                                currentScreen is Screen.PrivacyPolicy -> PrivacyPolicyScreen(onBack = { navigateBack() })
                            }
                        }
                    }
                }
            }

            // Badge animacija overlay (prikaže se čez vse)
            unlockedBadge?.let { badge ->
                com.example.myapplication.ui.components.BadgeUnlockAnimation(
                    badge = badge,
                    onDismiss = { unlockedBadge = null }
                )
            }
        }
    }

    private fun firebaseAuthWithGoogle(
        acct: GoogleSignInAccount?,
        onSuccess: () -> Unit,
        onError: (String) -> Unit
    ) {
        val credential = GoogleAuthProvider.getCredential(acct?.idToken, null)
        Firebase.auth.signInWithCredential(credential).addOnCompleteListener(this) { task ->
            if (task.isSuccessful) onSuccess()
            else onError(task.exception?.localizedMessage ?: "Google sign-in failed.")
        }
    }
}

@file:Suppress("DEPRECATION") // Suppress deprecation warnings for GoogleSignIn usage until migration to Credential Manager

package com.example.myapplication

// =====================================================================
// MainActivity.kt
// Vsebuje: samo MainActivity class (onCreate, auth, app state, navigacija).
// Screen sealed class → AppNavigation.kt
// Drawer / Header     → AppDrawer.kt
// =====================================================================

import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.BackHandler
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.compose.setContent
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.runtime.derivedStateOf
import androidx.compose.runtime.rememberCoroutineScope
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.compose.material3.DrawerValue
import androidx.compose.material3.rememberDrawerState
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.myapplication.data.settings.UserProfileManager
import com.example.myapplication.network.OpenFoodFactsProduct
import com.example.myapplication.persistence.PlanDataStore
import com.example.myapplication.ui.home.CommunityScreen
import com.example.myapplication.ui.screens.*
import com.example.myapplication.data.PlanResult
import com.example.myapplication.ui.theme.MyApplicationTheme
import com.example.myapplication.utils.HapticFeedback
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.firebase.auth.GoogleAuthProvider
import com.google.firebase.auth.ktx.auth
import com.google.firebase.ktx.Firebase
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import kotlinx.coroutines.tasks.await


class MainActivity : ComponentActivity() {
    private lateinit var googleSignInClient: GoogleSignInClient

    // Store intent extras to trigger effects
    private val intentExtras = mutableStateOf<Bundle?>(null)

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        intentExtras.value = intent.extras
    }

    override fun onPause() {
        super.onPause()
        try {
            com.example.myapplication.worker.DailySyncWorker.schedule(this)
        } catch (_: Exception) {}
    }

    private var isSubscribed = false
    private var paymentStatus: String? = null

    // Performance timer
    private var coldStartEpochMs: Long = 0L

    // Push notification permission launcher
    private val requestNotificationPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { isGranted: Boolean ->
            Log.d("MainActivity", "Notification permission granted: $isGranted")
        }

    @Suppress("DEPRECATION")
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        coldStartEpochMs = android.os.SystemClock.elapsedRealtime()
        super.onCreate(savedInstanceState)

        // Eager load AdvancedExerciseRepository in background immediately upon app startup
        kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
            val jsonString = applicationContext.assets.open("exercises.json").bufferedReader().use { it.readText() }
            com.example.myapplication.data.AdvancedExerciseRepository.init(jsonString)
        }

        intentExtras.value = intent.extras

        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(getString(R.string.default_web_client_id))
            .requestEmail()
            .build()
        googleSignInClient = GoogleSignIn.getClient(this, gso)

        setContent {
            // First paint measurement
            LaunchedEffect(Unit) {
                val timeToPaint = android.os.SystemClock.elapsedRealtime() - coldStartEpochMs
                Log.i("AppPerf", " First paint arrived at: $timeToPaint ms")
            }

            val context = LocalContext.current
            val bodyOverviewViewModel: BodyOverviewViewmodel =
                viewModel(factory = MyViewModelFactory())
            val plans: List<com.example.myapplication.data.PlanResult> by bodyOverviewViewModel.plans.collectAsState()

            val appViewModel: AppViewModel = viewModel()
            val userProfile by appViewModel.userProfile.collectAsState()

            val networkObserver = remember { com.example.myapplication.utils.NetworkObserver(context) }
            val isOnline by networkObserver.observe().collectAsState(initial = true)

            val navViewModel: NavigationViewModel = viewModel()
            val currentScreen by navViewModel.currentScreen.collectAsState()
            val previousScreen by navViewModel.previousScreen.collectAsState()

            var isCheckingAuth by remember { mutableStateOf(true) }

            // ----- Auth stanje -----
            var isLoggedIn by remember { mutableStateOf(false) }
            var userEmail by remember { mutableStateOf("") }
            var errorMessage by remember { mutableStateOf<String?>(null) }
            var isDarkMode by remember { mutableStateOf(false) }

            // ----- Vadba stanje -----
            var selectedPlan by remember { mutableStateOf<PlanResult?>(null) }
            var isExtraWorkoutSession by remember { mutableStateOf(false) }
            var extraFocusAreas by remember { mutableStateOf<List<String>>(emptyList()) }
            var extraEquipment by remember { mutableStateOf<Set<String>>(emptySet()) }

            // ----- Prehrana stanje -----
            var scannedProduct by remember { mutableStateOf<Pair<OpenFoodFactsProduct, String>?>(null) }
            val nutritionSnackbarHostState = remember { SnackbarHostState() }

            // ----- Badge animacija -----
            var unlockedBadge by remember { mutableStateOf<com.example.myapplication.data.Badge?>(null) }

            val scope = rememberCoroutineScope()
            val drawerState = rememberDrawerState(DrawerValue.Closed)

            var pendingNavigateToNutrition by remember { mutableStateOf(false) }
            var pendingOpenBarcodeScan by remember { mutableStateOf(false) }
            var pendingOpenFoodSearch by remember { mutableStateOf(false) }

            val googleSignInLauncher = rememberLauncherForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
                val task = GoogleSignIn.getSignedInAccountFromIntent(result.data)
                try {
                    val account = task.getResult(com.google.android.gms.common.api.ApiException::class.java)
                    firebaseAuthWithGoogle(account, onSuccess = {
                        val user = Firebase.auth.currentUser
                        if (user != null && user.email != null) {
                            isLoggedIn = true; userEmail = user.email!!
                            appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                            scope.launch { isDarkMode = UserProfileManager.isDarkMode(userEmail) }
                            navViewModel.clearStack(); navViewModel.navigateTo(Screen.Dashboard)
                        } else errorMessage = "Google sign-in error."
                    }, onError = { err -> errorMessage = err })
                } catch (e: Exception) { errorMessage = "Google sign-in failed: ${e.localizedMessage}" }
            }

            // === INITIAL AUTH & SYNC FLOW ===
            LaunchedEffect(Unit) {
                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                val accountEmail = com.google.firebase.ktx.Firebase.auth.currentUser?.email

                // Preveri fresh_start flag (nastavljen ob delete data/account)
                val appFlags = context.getSharedPreferences("app_flags", Context.MODE_PRIVATE)
                if (appFlags.getBoolean("fresh_start_on_login", false)) {
                    // Pobriši vse bm_prefs na čisto — novo začetno stanje
                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                        .edit().clear().apply()
                    context.getSharedPreferences("algorithm_prefs", Context.MODE_PRIVATE)
                        .edit().clear().apply()
                    // Počisti flag
                    appFlags.edit().remove("fresh_start_on_login").apply()
                    Log.d("MainActivity", "✅ Fresh start: bm_prefs reset")
                }

                // ── Faza 5: One-time migracija — pobriši stare lokalne SharedPrefs caches ──
                // water_cache, burned_cache, calories_cache, food_cache so bili legaccy
                // vmesni buffer za sync. Firestore SDK (isPersistenceEnabled=true) zdaj
                // skrbi za offline delovanje sam — te datoteke niso več potrebne.
                val migPrefs = context.getSharedPreferences("migration_flags", Context.MODE_PRIVATE)
                if (!migPrefs.getBoolean("faza5_legacy_purge_done", false)) {
                    com.example.myapplication.persistence.DailySyncManager.clearLegacyCache(context)
                    migPrefs.edit().putBoolean("faza5_legacy_purge_done", true).apply()
                    Log.i("MainActivity", "✅ Faza 5: Legacy lokalni cache počiščen → Firestore je Single Source of Truth")
                }
                // ──────────────────────────────────────────────────────────────────────────

                    if (accountEmail != null) {
                        userEmail = accountEmail

                        // Nastavi uporabniški profil
                        appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                        isDarkMode = UserProfileManager.isDarkMode(userEmail)

                    // Preveri in sinhroniziraj badge ob zagonu
                    try {
                        val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                        useCase.checkAndSyncBadgesOnStartup()
                    }
                    catch (e: Exception) { Log.e("MainActivity", "Badge sync error: ${e.message}") }

                    // Sinhronizacija načrtov
                    try { PlanDataStore.migrateLocalPlansToFirestore(context) } catch (_: Exception) {}
                    bodyOverviewViewModel.refreshPlans()

                    // Osveži podatke o profilu iz Firestore
                    kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
                        try {
                            val remote = UserProfileManager.loadProfileFromFirestore(userEmail)
                            if (remote != null) {
                                UserProfileManager.saveProfile(remote)
                                val actParsed = remote.activityLevel?.replace("x", "")?.toIntOrNull()
                                if (actParsed != null && actParsed > 0) {
                                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        .edit().putInt("weekly_target", actParsed).apply()
                                }
                                withContext(Dispatchers.Main) { appViewModel.handleIntent(AppIntent.SetProfile(remote)) }
                            }
                        } catch (_: Exception) {}
                    }

                    // Nastavitev start poslušanja s pomočjo UseCase
                    appViewModel.handleIntent(AppIntent.StartListening(userEmail))
                }
                isCheckingAuth = false
            }

            // ----- Auth check ob zagonu -----
            LaunchedEffect(Unit) {
                val user = Firebase.auth.currentUser
                if (user != null && (user.isEmailVerified || user.providerData.any { it.providerId == "google.com" })) {
                    isLoggedIn = true
                    userEmail = user.email ?: ""

                    appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                    isDarkMode = UserProfileManager.isDarkMode(userEmail)
                    navViewModel.navigateTo(if (pendingNavigateToNutrition) Screen.Nutrition else Screen.Dashboard)

                    scope.launch(Dispatchers.IO) {
                        try {
                            val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                            useCase.recordLoginOnly()
                        }
                        catch (e: Exception) { Log.e("MainActivity", "Login streak error: ${e.message}") }
                    }
                    scope.launch(Dispatchers.IO) {
                        try {
                            val profile = UserProfileManager.loadProfile(userEmail)
                            com.example.myapplication.workers.WeeklyStreakWorker.ensureScheduled(context, profile.startOfWeek)
                        } catch (e: Exception) { Log.e("MainActivity", "WeeklyStreakWorker error: ${e.message}") }
                    }

                    // Tedenski čistilec starih GPS run_routes .json datotek
                    try {
                        com.example.myapplication.worker.RunRouteCleanupWorker.ensureScheduled(context)
                    } catch (e: Exception) { Log.e("MainActivity", "RunRouteCleanupWorker error: ${e.message}") }

                    delay(250)
                    scope.launch(Dispatchers.IO) {
                        try {
                            val remote = UserProfileManager.loadProfileFromFirestore(userEmail)
                            if (remote != null) {
                                UserProfileManager.saveProfile(remote)
                                val actParsed = remote.activityLevel?.replace("x", "")?.toIntOrNull()
                                if (actParsed != null && actParsed > 0) {
                                    context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        .edit().putInt("weekly_target", actParsed).apply()
                                }
                                withContext(Dispatchers.Main) { appViewModel.handleIntent(AppIntent.SetProfile(remote)) }
                            }
                        } catch (_: Exception) {}
                    }
                    scope.launch(Dispatchers.IO) {
                        delay(1500)
                        try {
                            val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                            useCase.checkAndSyncBadgesOnStartup()
                        }
                        catch (e: Exception) { Log.e("MainActivity", "Badge sync error: ${e.message}") }
                    }
                    scope.launch {
                        try { PlanDataStore.migrateLocalPlansToFirestore(context) } catch (_: Exception) {}
                        bodyOverviewViewModel.refreshPlans()
                        try { com.example.myapplication.widget.StreakWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                        try { com.example.myapplication.widget.PlanDayWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                        val syncUid = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId()
                        if (syncUid != null) {
                            try { com.example.myapplication.persistence.DailySyncManager.syncOnAppOpen(context, syncUid) } catch (_: Exception) {}
                        }
                    }

                    // Real-time Firestore listener — kliče loadProfileFromFirestore() (ni ročnega gradnje UserProfile)
                    appViewModel.handleIntent(AppIntent.StartListening(userEmail))
                } else {
                    navViewModel.navigateTo(Screen.Index)
                }
                isCheckingAuth = false
            }

            // ----- Workers scheduling ob loginu (email, Google, auto-login) -----
            LaunchedEffect(isLoggedIn) {
                if (isLoggedIn) {
                    try {
                        com.example.myapplication.workers.StreakReminderWorker.createNotificationChannel(context)
                        com.example.myapplication.workers.StreakReminderWorker.scheduleForToday(context)
                    } catch (e: Exception) { Log.e("MainActivity", "StreakReminderWorker schedule error: ${e.message}") }
                }
            }

            // ----- Widget intent handling -----
            var showWeightInputDialog by remember { mutableStateOf(false) }
            var openBarcodeScan by remember { mutableStateOf(false) }
            var openFoodSearch by remember { mutableStateOf(false) }
            var pendingNavigateToBodyModule by remember { mutableStateOf(false) }

            LaunchedEffect(intentExtras.value) {
                val extras = intentExtras.value ?: return@LaunchedEffect
                Log.d("MainActivity", "Intent extras: NAVIGATE_TO=${extras.getString("NAVIGATE_TO")}")
                if (extras.getBoolean("OPEN_WEIGHT_INPUT", false)) {
                    showWeightInputDialog = true
                    if (isLoggedIn) navViewModel.navigateTo(Screen.Progress)
                }
                if (extras.getString("NAVIGATE_TO") == "nutrition") {
                    val wantsScan = extras.getBoolean("OPEN_BARCODE_SCAN", false)
                    val wantsSearch = extras.getBoolean("OPEN_FOOD_SEARCH", false)
                    if (isLoggedIn && !isCheckingAuth) {
                        navViewModel.navigateTo(Screen.Nutrition)
                        delay(150)
                        if (wantsScan) openBarcodeScan = true
                        if (wantsSearch) openFoodSearch = true
                    } else {
                        pendingNavigateToNutrition = true
                        pendingOpenBarcodeScan = wantsScan
                        pendingOpenFoodSearch = wantsSearch
                    }
                }
                if (extras.getString("NAVIGATE_TO") == "body_module") {
                    if (isLoggedIn && !isCheckingAuth) {
                        navViewModel.navigateTo(Screen.BodyModuleHome)
                    } else {
                        pendingNavigateToBodyModule = true
                    }
                }
            }

            LaunchedEffect(isCheckingAuth, isLoggedIn, pendingNavigateToBodyModule) {
                if (!isCheckingAuth && isLoggedIn && pendingNavigateToBodyModule) {
                    navViewModel.navigateTo(Screen.BodyModuleHome)
                    pendingNavigateToBodyModule = false
                }
            }

            LaunchedEffect(isCheckingAuth, isLoggedIn, pendingNavigateToNutrition, pendingOpenBarcodeScan, pendingOpenFoodSearch) {
                if (!isCheckingAuth && isLoggedIn && pendingNavigateToNutrition) {
                    navViewModel.navigateTo(Screen.Nutrition)
                    delay(150)
                    if (pendingOpenBarcodeScan) openBarcodeScan = true
                    if (pendingOpenFoodSearch) openFoodSearch = true
                    pendingNavigateToNutrition = false; pendingOpenBarcodeScan = false; pendingOpenFoodSearch = false
                }
            }

            // ----- Navigacijski pomočniki -----
            fun navigateTo(screen: Screen) = navViewModel.navigateTo(screen)

            fun navigateBack() = navViewModel.navigateBack(
                isLoggedIn = isLoggedIn,
                hasSelectedPlan = selectedPlan != null,
                onClearSelectedPlan = { selectedPlan = null },
                onClearError = { errorMessage = null },
                onFinish = { finish() }
            )

            BackHandler { navigateBack() }

            val shouldUseDarkMode = if (!isLoggedIn && currentScreen is Screen.Index) true else isDarkMode

            MyApplicationTheme(darkTheme = shouldUseDarkMode) {
                if (isCheckingAuth) {
                    Box(
                        modifier = Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background),
                        contentAlignment = Alignment.Center
                    ) { CircularProgressIndicator(color = MaterialTheme.colorScheme.tertiary) }
                } else if (isLoggedIn) {
                    val enableDrawerGestures = when (currentScreen) {
                        is Screen.Dashboard, is Screen.Progress, is Screen.BodyModuleHome,
                        is Screen.BodyOverview, is Screen.MyPlans, is Screen.FaceModule,
                        is Screen.HairModule, is Screen.Shop,
                        is Screen.Community, is Screen.MyAccount, is Screen.ExerciseHistory,
                        is Screen.ManualExerciseLog, is Screen.Nutrition -> true
                        else -> currentScreen !is Screen.RunTracker && currentScreen !is Screen.ActivityLog
                    }

                    ModalNavigationDrawer(
                        drawerState = drawerState,
                        gesturesEnabled = enableDrawerGestures,
                        drawerContent = {
                            FigmaDrawerContent(
                                userProfile = userProfile,
                                onClose = { scope.launch { drawerState.close() } },
                                onLogout = {
                                    com.google.firebase.ktx.Firebase.auth.signOut()
                                    googleSignInClient.signOut()
                                    com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                    appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                    val lp = context.getSharedPreferences("local_prefs", Context.MODE_PRIVATE)
                                    lp.edit().putString("fcm_token", "").apply()
                                    isLoggedIn = false
                                    navViewModel.clearStack()
                                },
                                                onProfileUpdate = { updatedProfile ->
                                                    appViewModel.handleIntent(AppIntent.SetProfile(updatedProfile))
                                                    UserProfileManager.saveProfile(updatedProfile)
                                                    scope.launch { UserProfileManager.saveProfileFirestore(updatedProfile) }
                                                },
                                                isDarkMode = isDarkMode,
                                onDarkModeToggle = {
                                    isDarkMode = !isDarkMode
                                    scope.launch { UserProfileManager.setDarkMode(userEmail, isDarkMode) }
                                },
                                onNavigateToPrivacyPolicy = { navigateTo(Screen.PrivacyPolicy); scope.launch { drawerState.close() } },
                                onNavigateToTermsOfService = { navigateTo(Screen.TermsOfService); scope.launch { drawerState.close() } },
                                onNavigateToContact = { navigateTo(Screen.Contact); scope.launch { drawerState.close() } },
                                onNavigateToAbout = { navigateTo(Screen.About); scope.launch { drawerState.close() } },
                                onNavigateToAchievements = { navigateTo(Screen.Achievements); scope.launch { drawerState.close() } },
                                onNavigateToBadges = { navigateTo(Screen.Achievements); scope.launch { drawerState.close() } },
                                onNavigateToHealthConnect = { navigateTo(Screen.HealthConnect); scope.launch { drawerState.close() } },
                                onNavigateToDebugDashboard = { navigateTo(Screen.DebugDashboard); scope.launch { drawerState.close() } },
                                onNavigateToMyAccount = { navigateTo(Screen.MyAccount); scope.launch { drawerState.close() } }
                            )
                        }
                    ) {
                        val showBottomBar by remember {
                            derivedStateOf {
                                isLoggedIn && selectedPlan == null && when (currentScreen) {
                                    is Screen.Dashboard, is Screen.Progress, is Screen.BodyOverview,
                                    is Screen.MyPlans, is Screen.BodyModuleHome, is Screen.Nutrition,
                                    is Screen.Community, is Screen.MyAccount, is Screen.FaceModule,
                                    is Screen.HairModule, is Screen.Shop -> true
                                    else -> false
                                }
                            }
                        }

                        Scaffold(
                            topBar = {
                                if (currentScreen is Screen.Dashboard) {
                                    GlobalHeaderBar(
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        }
                                    )
                                }
                            },
                            snackbarHost = {
                                SnackbarHost(
                                    hostState = nutritionSnackbarHostState,
                                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 12.dp)
                                ) { data ->
                                    Surface(
                                        color = MaterialTheme.colorScheme.surface,
                                        contentColor = MaterialTheme.colorScheme.onSurface,
                                        shape = RoundedCornerShape(20.dp),
                                        tonalElevation = 6.dp, shadowElevation = 8.dp,
                                        modifier = Modifier.fillMaxWidth()
                                    ) {
                                        Row(modifier = Modifier.padding(horizontal = 18.dp, vertical = 12.dp), verticalAlignment = Alignment.CenterVertically) {
                                            Text(data.visuals.message, style = MaterialTheme.typography.bodyMedium)
                                        }
                                    }
                                }
                            },
                            bottomBar = {
                                if (showBottomBar) {
                                    AppBottomBar(currentScreen = currentScreen, onSelect = { target ->
                                        selectedPlan = null; navigateTo(target)
                                    })
                                }
                            },
                            containerColor = MaterialTheme.colorScheme.background
                        ) { innerPadding ->
                            val shouldApplyPadding = currentScreen !is Screen.Progress && currentScreen !is Screen.Nutrition && currentScreen !is Screen.Community
                            Box(modifier = Modifier.fillMaxSize().then(if (shouldApplyPadding) Modifier.padding(innerPadding) else Modifier)) {
                                // ============================================================
                                // SCREEN ROUTING — vsak zaslon ima svojo vrstico
                                // Za dodajanje novega zaslona: dodaj Screen objekt v AppNavigation.kt
                                // in dodaj when blok tukaj.
                                // ============================================================
                                when {
                                    currentScreen is Screen.LoadingWorkout -> LoadingWorkoutScreen(
                                        onLoadingComplete = {
                                            scope.launch {
                                                isExtraWorkoutSession = false
                                                // replaceTo() namesto navigateTo() — LoadingWorkout NE gre v back-stack,
                                                // Back iz WorkoutSession gre direktno na BodyModuleHome (popTo).
                                                navViewModel.replaceTo(Screen.WorkoutSession)
                                            }
                                        }
                                    )
                                    currentScreen is Screen.BodyModuleHome -> BodyModuleHomeScreen(
                                        onBack = { navigateBack() },
                                        onStartPlan = { navigateTo(Screen.BodyOverview) },
                                        onStartWorkout = { plan ->
                                            if (plan == null) { navigateTo(Screen.BodyOverview); return@BodyModuleHomeScreen }
                                            selectedPlan = plan; navigateTo(Screen.LoadingWorkout)
                                        },
                                        onStartAdditionalWorkout = { navigateTo(Screen.GenerateWorkout) },
                                        currentPlan = plans.maxByOrNull { it.createdAt },
                                        onOpenHistory = { navigateTo(Screen.ExerciseHistory) },
                                        onOpenManualLog = { navigateTo(Screen.ManualExerciseLog) },
                                        onStartRun = { navigateTo(Screen.RunTracker) },
                                        onOpenActivityLog = { navigateTo(Screen.ActivityLog) }
                                    )
                                    currentScreen is Screen.ActivityLog -> ActivityLogScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.WorkoutSession -> {
                                        val frozenPlan = remember(currentScreen) { selectedPlan ?: plans.maxByOrNull { it.createdAt } }
                                        WorkoutSessionScreen(
                                            currentPlan = frozenPlan,
                                            isExtra = isExtraWorkoutSession,
                                            extraFocusAreas = extraFocusAreas,
                                            extraEquipment = extraEquipment,
                                            onBack = {
                                                selectedPlan = null; isExtraWorkoutSession = false
                                                extraFocusAreas = emptyList(); extraEquipment = emptySet()
                                                navViewModel.popTo(Screen.BodyModuleHome)
                                            },
                                            onFinished = {
                                                selectedPlan = null; isExtraWorkoutSession = false
                                                extraFocusAreas = emptyList(); extraEquipment = emptySet()
                                                navViewModel.popTo(Screen.BodyModuleHome)
                                                // Posodobi Plan Day widget takoj po končani vadbi
                                                try { com.example.myapplication.widget.PlanDayWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                                                try { com.example.myapplication.widget.StreakWidgetProvider.refreshAll(context) } catch (_: Exception) {}
                                            },
                                            onXPAdded = { appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail))) },
                                            onBadgeUnlocked = { badge ->
                                                unlockedBadge = badge
                                                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                            }
                                        )
                                    }
                                    currentScreen is Screen.FaceModule -> FaceModuleScreen(
                                        onBack = { navigateBack() }
                                    )

                                    currentScreen is Screen.HairModule -> HairModuleScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Shop -> ShopScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Progress -> ProgressScreen(
                                        openWeightInput = showWeightInputDialog,
                                        userProfile = userProfile,
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        }
                                    )
                                    currentScreen is Screen.Nutrition -> {
                                        NutritionScreen(
                                            plan = plans.maxByOrNull { it.createdAt },
                                            onScanBarcode = { openBarcodeScan = false; navigateTo(Screen.BarcodeScanner) },
                                            scannedProduct = scannedProduct,
                                            onProductConsumed = { scannedProduct = null },
                                            openBarcodeScan = openBarcodeScan,
                                            openFoodSearch = openFoodSearch,
                                            onXPAdded = { appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail))) },
                                            snackbarHostState = nutritionSnackbarHostState,
                                            userProfile = userProfile,
                                            isOnline = isOnline,
                                            onOpenMenu = {
                                                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                                scope.launch { drawerState.open() }
                                            },
                                            onProClick = {
                                                errorMessage = null
                                                navViewModel.navigateTo(Screen.ProFeatures)
                                            },
                                            // ✅ Faza 16.3: E-Additives navigacija
                                            onOpenAdditives = { navigateTo(Screen.EAdditives) }
                                        )
                                    }
                                    currentScreen is Screen.BarcodeScanner -> BarcodeScannerScreen(
                                        onDismiss = { navigateBack() },
                                        onProductScanned = { product, barcode -> scannedProduct = Pair(product, barcode); navigateBack() }
                                    )
                                    // ✅ Faza 16.3: E-Additives zaslon
                                    currentScreen is Screen.EAdditives -> com.example.myapplication.ui.screens.EAdditivesScreen(
                                        onNavigateBack = { navigateBack() }
                                    )

                                    currentScreen is Screen.ExerciseHistory -> ExerciseHistoryScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.ManualExerciseLog -> ManualExerciseLogScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.RunTracker -> RunTrackerScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.GenerateWorkout -> GenerateWorkoutScreen(
                                        onBack = { navigateBack() },
                                        currentPlan = plans.maxByOrNull { it.createdAt },
                                        onSelectWorkout = { generatedWorkout ->
                                            val latestPlan = plans.maxByOrNull { it.createdAt }
                                            if (latestPlan != null) {
                                                isExtraWorkoutSession = true
                                                extraFocusAreas = generatedWorkout.focus.split(",").map { it.trim() }.filter { it.isNotBlank() }
                                                extraEquipment = generatedWorkout.equipment.ifEmpty { setOf("bodyweight") }
                                                selectedPlan = latestPlan
                                                navigateTo(Screen.WorkoutSession)
                                            } else navigateTo(Screen.BodyOverview)
                                        }
                                    )
                                    currentScreen is Screen.Community -> CommunityScreen(
                                        isOnline = isOnline,
                                        onOpenMenu = {
                                            HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.DRAWER_OPEN)
                                            scope.launch { drawerState.open() }
                                        },
                                        onProClick = {
                                            errorMessage = null
                                            navViewModel.navigateTo(Screen.ProFeatures)
                                        },
                                        onViewProfile = { userId -> navigateTo(Screen.PublicProfile(userId)) }
                                    )
                                    currentScreen is Screen.BodyOverview -> BodyOverviewScreen(
                                        plans = plans,
                                        onCreateNewPlan = { navigateTo(Screen.BodyModule) },
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.Dashboard -> {
                                        com.example.myapplication.ui.screens.DashboardScreen(
                                            userEmail = userEmail,
                                            onLogout = {
                                                com.google.firebase.ktx.Firebase.auth.signOut()
                                                googleSignInClient.signOut()
                                                com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                                appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                                isLoggedIn = false
                                                navViewModel.clearStack()
                                            },
                                            onModuleClick = { module ->
                                                when(module) {
                                                    "Body" -> navigateTo(Screen.BodyModuleHome)
                                                    "Face" -> navigateTo(Screen.FaceModule)
                                                    "Hair" -> navigateTo(Screen.HairModule)
                                                    "Shop" -> navigateTo(Screen.Shop)
                                                }
                                            },
                                            onAccountClick = { navigateTo(Screen.MyAccount) },
                                            onProClick = { navigateTo(Screen.ProFeatures) },
                                            onOpenMenu = {
                                                com.example.myapplication.utils.HapticFeedback.performHapticFeedback(context, com.example.myapplication.utils.HapticFeedback.FeedbackType.DRAWER_OPEN)
                                                scope.launch { drawerState.open() }
                                            },
                                            showLocalHeader = false
                                        )
                                    }
                                    currentScreen is Screen.ProFeatures -> ProFeaturesScreen(
                                        onFreeTrial = {},
                                        onContinue = { if (isLoggedIn) { errorMessage = null; navigateTo(Screen.ProSubscription) } },
                                        onBack = { errorMessage = null; navigateBack() },
                                        errorMessage = errorMessage
                                    )
                                    currentScreen is Screen.BodyModule -> BodyPlanQuizScreen(
                                        onBack = { navigateBack() },
                                        onQuizDataCollected = { quizData ->
                                            @Suppress("UNCHECKED_CAST")
                                            val limitationsList = quizData["limitations"] as? List<String> ?: emptyList()
                                            Log.d("MainActivity", "onQuizDataCollected: height=${quizData["height"]}")
                                            val newHeight = (quizData["height"] as? Number)?.toDouble() ?: (quizData["height"] as? String)?.toDoubleOrNull()
                                            val newAge = (quizData["age"] as? Number)?.toInt() ?: (quizData["age"] as? String)?.toIntOrNull()
                                            val newGender = quizData["gender"] as? String
                                            val updatedFromQuiz = userProfile.copy(
                                                height = newHeight, age = newAge, gender = newGender,
                                                activityLevel = quizData["frequency"] as? String,
                                                experience = quizData["experience"] as? String,
                                                bodyFat = quizData["bodyFat"] as? String,
                                                workoutGoal = quizData["goal"] as? String ?: "",
                                                limitations = limitationsList,
                                                nutritionStyle = quizData["nutrition"] as? String,
                                                sleepHours = quizData["sleep"] as? String
                                            )
                                            appViewModel.handleIntent(AppIntent.SetProfile(updatedFromQuiz))
                                            UserProfileManager.saveProfile(updatedFromQuiz)
                                            scope.launch { UserProfileManager.saveProfileFirestore(updatedFromQuiz) }

                                            val freqStr = quizData["frequency"] as? String
                                            val freqParsed = freqStr?.replace("x", "")?.replace("X", "")?.trim()?.toIntOrNull()
                                            if (freqParsed != null && freqParsed > 0) {
                                                context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                                    .edit().putInt("weekly_target", freqParsed).apply()
                                                Log.d("MainActivity", "weekly_target set from quiz: $freqParsed")
                                            }
                                        },
                                        onFinish = { plan ->
                                            scope.launch {
                                                if (plans.isNotEmpty()) plans.forEach { PlanDataStore.deletePlan(context, it.id) }
                                                PlanDataStore.addPlan(context, plan)
                                                var currentProfile = userProfile
                                                if (currentProfile.height == null || currentProfile.height == 0.0)
                                                    currentProfile = UserProfileManager.loadProfile(userEmail)
                                                val finalProfile = currentProfile.copy(equipment = plan.equipment, focusAreas = plan.focusAreas)
                                                UserProfileManager.saveProfileFirestore(finalProfile)
                                                UserProfileManager.saveProfile(finalProfile)
                                                appViewModel.handleIntent(AppIntent.SetProfile(finalProfile))
                                                val useCase = com.example.myapplication.domain.gamification.GamificationProvider.provide(context)
                                                useCase.recordPlanCreation()
                                                appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                                val uid = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId()
                                                if (uid != null) {
                                                    val nutritionPlan = com.example.myapplication.data.NutritionPlan(
                                                        calories = plan.calories, protein = plan.protein,
                                                        carbs = plan.carbs, fat = plan.fat,
                                                        algorithmData = plan.algorithmData,
                                                        lastUpdated = System.currentTimeMillis()
                                                    )
                                                    com.example.myapplication.persistence.NutritionPlanStore.saveNutritionPlan(uid, nutritionPlan)
                                                }
                                                val freqFromPlan = plan.trainingDays.takeIf { it > 0 }
                                                val actParsed = userProfile.activityLevel?.replace("x", "")?.replace("X", "")?.trim()?.toIntOrNull()
                                                val weeklyTargetToSave = actParsed?.takeIf { it > 0 } ?: freqFromPlan ?: 3
                                                // ✅ Global Audit (Faza 13.3): NE beremo streak/total/lastEpoch iz bm_prefs (deprecated).
                                                // Ob novem planu posodabljamo SAMO plan-specifична polja: plan_day=1, weekly_target, weekly_done=0.
                                                // streak_days ostane nespremenjen v Firestoreu — user ne izgubi streaka pri zamenjavi plana.
                                                if (userEmail.isNotBlank()) {
                                                    try {
                                                        com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocRef()
                                                            .set(
                                                                mapOf(
                                                                    "plan_day"      to 1,
                                                                    "weekly_target" to weeklyTargetToSave,
                                                                    "weekly_done"   to 0
                                                                ),
                                                                com.google.firebase.firestore.SetOptions.merge()
                                                            ).await()
                                                        android.util.Log.d("MainActivity", "✅ New plan init: plan_day=1, weekly_target=$weeklyTargetToSave (streak preserved)")
                                                    } catch (e: Exception) {
                                                        android.util.Log.e("MainActivity", "❌ New plan Firestore init failed: ${e.message}")
                                                    }
                                                }
                                                bodyOverviewViewModel.refreshPlans()
                                                navViewModel.navigateTo(Screen.BodyOverview)
                                            }
                                        }
                                    )
                                    currentScreen is Screen.ProSubscription -> ProSubscriptionScreen(
                                        onBack = { navigateBack() },
                                        onSubscribed = { navigateTo(Screen.Dashboard) }
                                    )
                                    currentScreen is Screen.MyPlans -> MyPlansScreen(
                                        plans = plans,
                                        onPlanClick = { plan -> selectedPlan = plan },
                                        onPlanDelete = { plan -> scope.launch { PlanDataStore.deletePlan(context, plan.id) } }
                                    )
                                    currentScreen is Screen.MyAccount -> MyAccountScreen(
                                        userProfile = userProfile,
                                        onNavigateToDevSettings = { navigateTo(Screen.DeveloperSettings) },
                                        onProfileUpdate = { updatedProfile ->
                                            appViewModel.handleIntent(AppIntent.SetProfile(updatedProfile))
                                            UserProfileManager.saveProfile(updatedProfile)
                                            scope.launch { UserProfileManager.saveProfileFirestore(updatedProfile) }
                                        },
                                        onDeleteAllData = {
                                            scope.launch {
                                                try {
                                                    UserProfileManager.deleteUserData(userEmail); PlanDataStore.deleteAllPlans()
                                                    PlanDataStore.clearPlan(context); UserProfileManager.clearAllLocalData()
                                                    bodyOverviewViewModel.clearPlans(); errorMessage = "All data deleted."
                                                } catch (e: Exception) { errorMessage = "Delete failed: ${e.localizedMessage}" }
                                            }
                                        },
                                        onDeleteAccount = {
                                            scope.launch {
                                                try {
                                                    UserProfileManager.deleteUserData(userEmail); PlanDataStore.deleteAllPlans()
                                                    PlanDataStore.clearPlan(context); UserProfileManager.clearAllLocalData()
                                                    com.example.myapplication.persistence.FirestoreHelper.clearCache()
                                                    try { Firebase.auth.currentUser?.delete()?.await() }
                                                    catch (reauth: com.google.firebase.auth.FirebaseAuthRecentLoginRequiredException) {
                                                        Firebase.auth.signOut()
                                                        errorMessage = "Account data deleted. Please sign in again and retry to fully delete account."
                                                    }
                                                    bodyOverviewViewModel.clearPlans(); isLoggedIn = false; userEmail = ""
                                                    appViewModel.handleIntent(AppIntent.SetProfile(com.example.myapplication.data.UserProfile(email = "")))
                                                    navViewModel.clearStack(); navViewModel.navigateTo(Screen.Index)
                                                    scope.launch { drawerState.close() }
                                                } catch (e: Exception) { errorMessage = "Account deletion failed: ${e.localizedMessage}" }
                                            }
                                        },
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.DeveloperSettings -> DeveloperSettingsScreen(
                                        onBack = { navigateBack() },
                                        userProfile = userProfile,
                                        currentPlan = plans.maxByOrNull { it.createdAt }
                                    )
                                    currentScreen is Screen.DebugDashboard -> com.example.myapplication.ui.screens.DebugDashboardScreen(
                                        onBack = { navigateBack() }
                                    )
                                    currentScreen is Screen.PrivacyPolicy -> PrivacyPolicyScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.TermsOfService -> TermsOfServiceScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Contact -> ContactScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.About -> AboutScreen(onBack = { navigateBack() })
                                    currentScreen is Screen.Achievements -> {
                                        val prefs = context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
                                        AchievementsScreen(
                                            userProfile = userProfile, activePlan = plans.firstOrNull(),
                                            currentPlanDay = prefs.getInt("plan_day", 1),
                                            weeklyDone = prefs.getInt("weekly_done", 0),
                                            onRefresh = { bodyOverviewViewModel.refreshPlans() },
                                            onBack = { navigateBack() }
                                        )
                                    }
                                    currentScreen is Screen.PublicProfile -> {
                                        val userId = (currentScreen as Screen.PublicProfile).userId
                                        var profileData by remember { mutableStateOf<com.example.myapplication.data.PublicProfile?>(null) }
                                        LaunchedEffect(userId) { profileData = com.example.myapplication.persistence.ProfileStore.getPublicProfile(userId) }
                                        profileData?.let { PublicProfileScreen(profile = it, onBack = { navigateBack() }) }
                                            ?: Box(Modifier.fillMaxSize(), Alignment.Center) { CircularProgressIndicator() }
                                    }
                                    currentScreen is Screen.HealthConnect -> HealthConnectScreen(
                                        onBack = { navigateBack() }
                                    )
                                }
                            }
                        }
                    }
                } else {
                    // Odjavljeni uporabnik
                    Scaffold(containerColor = MaterialTheme.colorScheme.background) { innerPadding ->
                        val shouldApplyPadding = currentScreen is Screen.Login
                        Box(modifier = Modifier.then(if (shouldApplyPadding) Modifier.padding(innerPadding) else Modifier)) {
                            when {
                                currentScreen is Screen.Index -> IndexScreen(
                                    onLoginClick = { errorMessage = null; navigateTo(Screen.Login(startInSignUp = false)) },
                                    onSignUpClick = { errorMessage = null; navigateTo(Screen.Login(startInSignUp = true)) },
                                    onViewProFeatures = { errorMessage = null; navigateTo(Screen.ProFeatures) }
                                )
                                currentScreen is Screen.Login -> LoginScreen(
                                    startInSignUp = (currentScreen as Screen.Login).startInSignUp,
                                    onForgotPassword = { email ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        Firebase.auth.sendPasswordResetEmail(email).addOnCompleteListener { task ->
                                            errorMessage = if (task.isSuccessful) "Password reset email sent to $email"
                                            else task.exception?.localizedMessage ?: "Failed to send reset email"
                                        }
                                    },
                                    onLogin = { email, password ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        if (password.isBlank()) { errorMessage = "Please enter your password."; return@LoginScreen }
                                        Firebase.auth.signInWithEmailAndPassword(email, password).addOnCompleteListener { task ->
                                            if (task.isSuccessful) {
                                                val user = Firebase.auth.currentUser
                                                if (user != null && user.isEmailVerified) {
                                                    isLoggedIn = true; userEmail = email
                                                    appViewModel.handleIntent(AppIntent.SetProfile(UserProfileManager.loadProfile(userEmail)))
                                                    scope.launch { isDarkMode = UserProfileManager.isDarkMode(userEmail) }
                                                    navViewModel.clearStack(); navViewModel.navigateTo(Screen.Dashboard)
                                                } else if (user != null) { errorMessage = "Please verify your email first!"; Firebase.auth.signOut() }
                                                else errorMessage = "Error: no user."
                                            } else errorMessage = task.exception?.localizedMessage ?: "Login failed."
                                        }
                                    },
                                    onSignup = { email, password, confirmPassword ->
                                        errorMessage = null
                                        if (email.isBlank()) { errorMessage = "Please enter your email."; return@LoginScreen }
                                        if (password.isBlank()) { errorMessage = "Please enter your password."; return@LoginScreen }
                                        if (password != confirmPassword) { errorMessage = "Passwords do not match."; return@LoginScreen }
                                        Firebase.auth.createUserWithEmailAndPassword(email, password).addOnCompleteListener { task ->
                                            if (task.isSuccessful) {
                                                Firebase.auth.currentUser?.sendEmailVerification()
                                                errorMessage = "Sign-up successful! Check your email to verify."
                                                Firebase.auth.signOut()
                                            } else errorMessage = task.exception?.localizedMessage ?: "Sign-up failed."
                                        }
                                    },
                                    onBackToHome = { errorMessage = null; navViewModel.navigateTo(Screen.Index) },
                                    errorMessage = errorMessage,
                                    onGoogleSignInClick = { errorMessage = null; googleSignInLauncher.launch(googleSignInClient.signInIntent) },
                                    onTermsClick = { navigateTo(Screen.TermsOfService) },
                                    onPrivacyClick = { navigateTo(Screen.PrivacyPolicy) }
                                )
                                currentScreen is Screen.ProFeatures -> ProFeaturesScreen(
                                    onFreeTrial = {},
                                    onContinue = { errorMessage = null; navigateTo(Screen.Login()) },
                                    onBack = { errorMessage = null; navigateBack() },
                                    errorMessage = errorMessage
                                )
                                currentScreen is Screen.TermsOfService -> TermsOfServiceScreen(onBack = { navigateBack() })
                                currentScreen is Screen.PrivacyPolicy -> PrivacyPolicyScreen(onBack = { navigateBack() })
                            }
                        }
                    }
                }
            }

            // Badge animacija overlay (prikaže se čez vse)
            unlockedBadge?.let { badge ->
                com.example.myapplication.ui.components.BadgeUnlockAnimation(
                    badge = badge,
                    onDismiss = { unlockedBadge = null }
                )
            }
        }
    }

    private fun firebaseAuthWithGoogle(
        acct: GoogleSignInAccount?,
        onSuccess: () -> Unit,
        onError: (String) -> Unit
    ) {
        val credential = GoogleAuthProvider.getCredential(acct?.idToken, null)
        Firebase.auth.signInWithCredential(credential).addOnCompleteListener(this) { task ->
            if (task.isSuccessful) onSuccess()
            else onError(task.exception?.localizedMessage ?: "Google sign-in failed.")
        }
    }
}

package com.example.myapplication.persistence

import android.util.Log
import com.example.myapplication.data.PublicActivity
import com.example.myapplication.data.PrivacySettings
import com.example.myapplication.data.PublicProfile
import com.example.myapplication.data.UserProfile
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.ktx.Firebase
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

object ProfileStore {
    private val firestore = Firebase.firestore

    /**
     * Update privacy settings for user
     */
    suspend fun updatePrivacySettings(
        email: String, // Kept for interface compatibility but ignored in favor of resolved ID
        settings: PrivacySettings
    ): Boolean = withContext(Dispatchers.IO) {
        try {
            val userRef = FirestoreHelper.getCurrentUserDocRef() // RESOLVED ID!

            val data = mapOf(
                "is_public_profile" to settings.isPublic,
                "show_level" to settings.showLevel,
                "show_badges" to settings.showBadges,
                "show_streak" to settings.showStreak, // Add showStreak
                "show_plan_path" to settings.showPlanPath,
                "show_challenges" to settings.showChallenges,
                "show_followers" to settings.showFollowers,
                "share_activities" to settings.shareActivities
            )

            userRef.update(data).await()

            Log.d("ProfileStore", "Updated privacy settings for ${userRef.id}")
            true
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error updating privacy settings: ${e.message}")
            false
        }
    }

    /**
     * Get public profile - returns only data that user has marked as public
     */
    suspend fun getPublicProfile(userId: String): PublicProfile? = withContext(Dispatchers.IO) {
        try {
            val doc = FirestoreHelper.getUserRef(userId).get().await()
            mapToPublicProfile(doc, fetchActivities = true)
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting public profile: ${e.message}")
            null
        }
    }

    /**
     * Internal mapper to convert DocumentSnapshot to PublicProfile
     */
    private suspend fun mapToPublicProfile(doc: com.google.firebase.firestore.DocumentSnapshot, fetchActivities: Boolean): PublicProfile? {
        if (!doc.exists()) return null

        // Check if profile is public
        val isPublic = doc.getBoolean("is_public_profile") ?: false
        if (!isPublic) return null

        // Get privacy flags
        val showLevel = doc.getBoolean("show_level") ?: false
        val showBadges = doc.getBoolean("show_badges") ?: false
        val showStreak = doc.getBoolean("show_streak") ?: false
        val showPlanPath = doc.getBoolean("show_plan_path") ?: false
        val showFollowers = doc.getBoolean("show_followers") ?: false
        val shareActivities = doc.getBoolean("share_activities") ?: false

        // Get basic data
        val userId = doc.id
        val username = doc.getString("username") ?: ""
        val displayName = doc.getString("first_name") ?: ""

        // Naloži javne aktivnosti (komprimirane rute) samo če je shareActivities=true AND fetchActivities=true
        val recentActivities: List<PublicActivity>? = if (shareActivities && fetchActivities) {
            try {
                val actSnap = FirestoreHelper.getUserRef(userId)
                    .collection("publicActivities")
                    .orderBy("startTime", com.google.firebase.firestore.Query.Direction.DESCENDING)
                    .limit(10)
                    .get()
                    .await()
                actSnap.documents.mapNotNull { d ->
                    try {
                        @Suppress("UNCHECKED_CAST")
                        val rawPts = d.get("routePoints") as? List<Map<String, Any>> ?: emptyList()
                        val pts = rawPts.mapNotNull { pt ->
                            val lat = (pt["lat"] as? Number)?.toDouble() ?: return@mapNotNull null
                            val lng = (pt["lng"] as? Number)?.toDouble() ?: return@mapNotNull null
                            Pair(lat, lng)
                        }
                        PublicActivity(
                            id = d.id,
                            activityType = d.getString("activityType") ?: "RUN",
                            distanceMeters = (d.get("distanceMeters") as? Number)?.toDouble() ?: 0.0,
                            durationSeconds = (d.get("durationSeconds") as? Number)?.toInt() ?: 0,
                            caloriesKcal = (d.get("caloriesKcal") as? Number)?.toInt() ?: 0,
                            elevationGainM = (d.get("elevationGainM") as? Number)?.toFloat() ?: 0f,
                            elevationLossM = (d.get("elevationLossM") as? Number)?.toFloat() ?: 0f,
                            avgSpeedMps = (d.get("avgSpeedMps") as? Number)?.toFloat() ?: 0f,
                            maxSpeedMps = (d.get("maxSpeedMps") as? Number)?.toFloat() ?: 0f,
                            startTime = (d.get("startTime") as? Number)?.toLong() ?: 0L,
                            routePoints = pts
                        )
                    } catch (_: Exception) { null }
                }
            } catch (_: Exception) { null }
        } else null

        // Filter data based on viewing permissions
        return PublicProfile(
            userId = userId,
            username = username,
            displayName = displayName,
            level = if (showLevel) (doc.get("xp") as? Number)?.toInt()?.let { xp ->
                com.example.myapplication.data.UserProfile.calculateLevel(xp)
            } else null,
            badges = if (showBadges) {
                when (val b = doc.get("badges")) {
                    is List<*> -> b.filterIsInstance<String>().map { badgeId ->
                        com.example.myapplication.data.BadgeDefinitions.getBadgeById(badgeId)
                            ?.copy(unlocked = true)
                    }.filterNotNull()
                    else -> null
                }
            } else null,
            streak = if (showStreak) (doc.get("streak_days") as? Number)?.toInt() ?: 0 else null,
            followers = if (showFollowers) (doc.get("followers") as? Number)?.toInt() else null,
            following = if (showFollowers) (doc.get("following") as? Number)?.toInt() else null,
            activePlanSummary = if (showPlanPath) null else null,
            recentActivities = recentActivities
        )
    }

    /**
     * Search for public profiles by username, email, or first name.
     * ⚡ OPTIMIZED: .limit(20) — preprečimo full-collection scan.
     * Vrne samo profile ki vsebujejo query v username/firstName/docId.
     */
    suspend fun searchPublicProfiles(query: String): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            Log.d("ProfileStore", " Searching for '$query'...")
            // Optimizacija: limit(20) — samo 20 dokumentov, client-side filter
            // (Firestore Android SDK ne podpira field projections ali full-text prefix index)
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .limit(20)
                .get()
                .await()

            Log.d("ProfileStore", " Fetched ${snapshot.size()} public profiles (max 20)")

            val results = snapshot.documents.mapNotNull { doc ->
                val username = doc.getString("username") ?: ""
                val firstName = doc.getString("first_name") ?: ""
                val docId = doc.id // email ali uid

                // Filtriramo samo nujna polja (name/username/id) — ne nalagamo badge/activity podatkov
                val matches = username.contains(query, ignoreCase = true) ||
                    firstName.contains(query, ignoreCase = true) ||
                    docId.contains(query, ignoreCase = true)

                if (matches) {
                    // Lightweight mapping: fetchActivities=false, samo name+photo+xp polja
                    mapToPublicProfile(doc, fetchActivities = false)
                } else null
            }
            Log.d("ProfileStore", " Returning ${results.size} matching profiles")
            results
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error searching profiles: ${e.message}")
            emptyList()
        }
    }

    /**
     * Get ALL public profiles (for Community Screen).
     * ⚡ OPTIMIZED: .limit(20) — varnostni strop za community tab.
     */
    suspend fun getAllPublicProfiles(): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .limit(20)
                .get()
                .await()

            snapshot.documents.mapNotNull { doc ->
                mapToPublicProfile(doc, fetchActivities = false)
            }
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting all profiles: ${e.message}")
            emptyList()
        }
    }

    /**
     * Get top users by follower count
     */
    suspend fun getTopUsers(limit: Int = 10): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .orderBy("followers", com.google.firebase.firestore.Query.Direction.DESCENDING)
                .limit(limit.toLong())
                .get()
                .await()

            snapshot.documents.mapNotNull { doc ->
                mapToPublicProfile(doc, fetchActivities = false)
            }
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting top users: ${e.message}")
            emptyList()
        }
    }
}

package com.example.myapplication.persistence

import android.util.Log
import com.example.myapplication.data.PublicActivity
import com.example.myapplication.data.PrivacySettings
import com.example.myapplication.data.PublicProfile
import com.example.myapplication.data.UserProfile
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.ktx.Firebase
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

object ProfileStore {
    private val firestore = Firebase.firestore

    /**
     * Update privacy settings for user
     */
    suspend fun updatePrivacySettings(
        email: String, // Kept for interface compatibility but ignored in favor of resolved ID
        settings: PrivacySettings
    ): Boolean = withContext(Dispatchers.IO) {
        try {
            val userRef = FirestoreHelper.getCurrentUserDocRef() // RESOLVED ID!

            val data = mapOf(
                "is_public_profile" to settings.isPublic,
                "show_level" to settings.showLevel,
                "show_badges" to settings.showBadges,
                "show_streak" to settings.showStreak, // Add showStreak
                "show_plan_path" to settings.showPlanPath,
                "show_challenges" to settings.showChallenges,
                "show_followers" to settings.showFollowers,
                "share_activities" to settings.shareActivities
            )

            userRef.update(data).await()

            Log.d("ProfileStore", "Updated privacy settings for ${userRef.id}")
            true
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error updating privacy settings: ${e.message}")
            false
        }
    }

    /**
     * Get public profile - returns only data that user has marked as public
     */
    suspend fun getPublicProfile(userId: String): PublicProfile? = withContext(Dispatchers.IO) {
        try {
            val doc = FirestoreHelper.getUserRef(userId).get().await()
            mapToPublicProfile(doc, fetchActivities = true)
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting public profile: ${e.message}")
            null
        }
    }

    /**
     * Internal mapper to convert DocumentSnapshot to PublicProfile
     */
    private suspend fun mapToPublicProfile(doc: com.google.firebase.firestore.DocumentSnapshot, fetchActivities: Boolean): PublicProfile? {
        if (!doc.exists()) return null

        // Check if profile is public
        val isPublic = doc.getBoolean("is_public_profile") ?: false
        if (!isPublic) return null

        // Get privacy flags
        val showLevel = doc.getBoolean("show_level") ?: false
        val showBadges = doc.getBoolean("show_badges") ?: false
        val showStreak = doc.getBoolean("show_streak") ?: false
        val showPlanPath = doc.getBoolean("show_plan_path") ?: false
        val showFollowers = doc.getBoolean("show_followers") ?: false
        val shareActivities = doc.getBoolean("share_activities") ?: false

        // Get basic data
        val userId = doc.id
        val username = doc.getString("username") ?: ""
        val displayName = doc.getString("first_name") ?: ""

        // Naloži javne aktivnosti (komprimirane rute) samo če je shareActivities=true AND fetchActivities=true
        val recentActivities: List<PublicActivity>? = if (shareActivities && fetchActivities) {
            try {
                val actSnap = FirestoreHelper.getUserRef(userId)
                    .collection("publicActivities")
                    .orderBy("startTime", com.google.firebase.firestore.Query.Direction.DESCENDING)
                    .limit(10)
                    .get()
                    .await()
                actSnap.documents.mapNotNull { d ->
                    try {
                        @Suppress("UNCHECKED_CAST")
                        val rawPts = d.get("routePoints") as? List<Map<String, Any>> ?: emptyList()
                        val pts = rawPts.mapNotNull { pt ->
                            val lat = (pt["lat"] as? Number)?.toDouble() ?: return@mapNotNull null
                            val lng = (pt["lng"] as? Number)?.toDouble() ?: return@mapNotNull null
                            Pair(lat, lng)
                        }
                        PublicActivity(
                            id = d.id,
                            activityType = d.getString("activityType") ?: "RUN",
                            distanceMeters = (d.get("distanceMeters") as? Number)?.toDouble() ?: 0.0,
                            durationSeconds = (d.get("durationSeconds") as? Number)?.toInt() ?: 0,
                            caloriesKcal = (d.get("caloriesKcal") as? Number)?.toInt() ?: 0,
                            elevationGainM = (d.get("elevationGainM") as? Number)?.toFloat() ?: 0f,
                            elevationLossM = (d.get("elevationLossM") as? Number)?.toFloat() ?: 0f,
                            avgSpeedMps = (d.get("avgSpeedMps") as? Number)?.toFloat() ?: 0f,
                            maxSpeedMps = (d.get("maxSpeedMps") as? Number)?.toFloat() ?: 0f,
                            startTime = (d.get("startTime") as? Number)?.toLong() ?: 0L,
                            routePoints = pts
                        )
                    } catch (_: Exception) { null }
                }
            } catch (_: Exception) { null }
        } else null

        // Filter data based on viewing permissions
        return PublicProfile(
            userId = userId,
            username = username,
            displayName = displayName,
            // ✅ Faza 15: shareActivities bere iz dokumenta GLEDANEGA uporabnika (ne lokalnih nastavitev)
            shareActivities = shareActivities,
            level = if (showLevel) (doc.get("xp") as? Number)?.toInt()?.let { xp ->
                com.example.myapplication.data.UserProfile.calculateLevel(xp)
            } else null,
            badges = if (showBadges) {
                when (val b = doc.get("badges")) {
                    is List<*> -> b.filterIsInstance<String>().map { badgeId ->
                        com.example.myapplication.data.BadgeDefinitions.getBadgeById(badgeId)
                            ?.copy(unlocked = true)
                    }.filterNotNull()
                    else -> null
                }
            } else null,
            streak = if (showStreak) (doc.get("streak_days") as? Number)?.toInt() ?: 0 else null,
            followers = if (showFollowers) (doc.get("followers") as? Number)?.toInt() else null,
            following = if (showFollowers) (doc.get("following") as? Number)?.toInt() else null,
            activePlanSummary = if (showPlanPath) null else null,
            recentActivities = recentActivities
        )
    }

    /**
     * Search for public profiles by username, email, or first name.
     * ⚡ OPTIMIZED: .limit(20) — preprečimo full-collection scan.
     * Vrne samo profile ki vsebujejo query v username/firstName/docId.
     */
    suspend fun searchPublicProfiles(query: String): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            Log.d("ProfileStore", " Searching for '$query'...")
            // Optimizacija: limit(20) — samo 20 dokumentov, client-side filter
            // (Firestore Android SDK ne podpira field projections ali full-text prefix index)
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .limit(20)
                .get()
                .await()

            Log.d("ProfileStore", " Fetched ${snapshot.size()} public profiles (max 20)")

            val results = snapshot.documents.mapNotNull { doc ->
                val username = doc.getString("username") ?: ""
                val firstName = doc.getString("first_name") ?: ""
                val docId = doc.id // email ali uid

                // Filtriramo samo nujna polja (name/username/id) — ne nalagamo badge/activity podatkov
                val matches = username.contains(query, ignoreCase = true) ||
                    firstName.contains(query, ignoreCase = true) ||
                    docId.contains(query, ignoreCase = true)

                if (matches) {
                    // Lightweight mapping: fetchActivities=false, samo name+photo+xp polja
                    mapToPublicProfile(doc, fetchActivities = false)
                } else null
            }
            Log.d("ProfileStore", " Returning ${results.size} matching profiles")
            results
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error searching profiles: ${e.message}")
            emptyList()
        }
    }

    /**
     * Get ALL public profiles (for Community Screen).
     * ⚡ OPTIMIZED: .limit(20) — varnostni strop za community tab.
     */
    suspend fun getAllPublicProfiles(): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .limit(20)
                .get()
                .await()

            snapshot.documents.mapNotNull { doc ->
                mapToPublicProfile(doc, fetchActivities = false)
            }
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting all profiles: ${e.message}")
            emptyList()
        }
    }

    /**
     * Get top users by follower count
     */
    suspend fun getTopUsers(limit: Int = 10): List<PublicProfile> = withContext(Dispatchers.IO) {
        try {
            val snapshot = firestore.collection("users")
                .whereEqualTo("is_public_profile", true)
                .orderBy("followers", com.google.firebase.firestore.Query.Direction.DESCENDING)
                .limit(limit.toLong())
                .get()
                .await()

            snapshot.documents.mapNotNull { doc ->
                mapToPublicProfile(doc, fetchActivities = false)
            }
        } catch (e: Exception) {
            Log.e("ProfileStore", "Error getting top users: ${e.message}")
            emptyList()
        }
    }
}

package com.example.myapplication.ui.components

import androidx.compose.animation.*
import androidx.compose.animation.core.*
import androidx.compose.foundation.Canvas
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.scale
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.example.myapplication.data.Badge
import kotlinx.coroutines.delay
import kotlin.math.cos
import kotlin.math.sin
import kotlin.random.Random

@Composable
fun BadgeUnlockAnimation(
    badge: Badge,
    onDismiss: () -> Unit
) {
    var visible by remember { mutableStateOf(false) }
    var iconScale by remember { mutableFloatStateOf(0f) }

    // Scale animation: 0 -> 1.5 -> 1.0
    val animatedScale by animateFloatAsState(
        targetValue = iconScale,
        animationSpec = spring(
            dampingRatio = Spring.DampingRatioMediumBouncy,
            stiffness = Spring.StiffnessLow
        ),
        label = "badgeScale"
    )

    // Auto-dismiss after 3 seconds
    LaunchedEffect(Unit) {
        visible = true
        delay(100)
        iconScale = 1.5f
        delay(300)
        iconScale = 1.0f
        delay(3000)
        onDismiss()
    }

    AnimatedVisibility(
        visible = visible,
        enter = fadeIn(animationSpec = tween(300)),
        exit = fadeOut(animationSpec = tween(300))
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.85f)),
            contentAlignment = Alignment.Center
        ) {
            // Confetti particles
            ConfettiEffect()

            // Badge unlock content
            Column(
                horizontalAlignment = Alignment.CenterHorizontally,
                modifier = Modifier.padding(32.dp)
            ) {
                Text(
                    "BADGE UNLOCKED!",
                    fontSize = 32.sp,
                    fontWeight = FontWeight.ExtraBold,
                    color = Color(0xFFFFD700),
                    textAlign = TextAlign.Center
                )

                Spacer(Modifier.height(32.dp))

                // Badge icon with scale animation
                Icon(
                    imageVector = getBadgeIcon(badge.iconName),
                    contentDescription = badge.name,
                    tint = Color(0xFFFFD700),
                    modifier = Modifier
                        .size(120.dp)
                        .scale(animatedScale)
                )

                Spacer(Modifier.height(24.dp))

                Text(
                    badge.name,
                    fontSize = 28.sp,
                    fontWeight = FontWeight.Bold,
                    color = Color.White,
                    textAlign = TextAlign.Center
                )

                Spacer(Modifier.height(12.dp))

                Text(
                    badge.description,
                    fontSize = 16.sp,
                    color = Color.White.copy(alpha = 0.8f),
                    textAlign = TextAlign.Center
                )

                Spacer(Modifier.height(32.dp))

                Button(
                    onClick = onDismiss,
                    colors = ButtonDefaults.buttonColors(
                        containerColor = Color(0xFFFFD700)
                    )
                ) {
                    Text("Continue", color = Color.Black, fontWeight = FontWeight.Bold)
                }
            }
        }
    }
}

@Composable
private fun ConfettiEffect() {
    var particles by remember {
        mutableStateOf(List(50) {
            ConfettiParticle(
                x = Random.nextFloat(),
                y = -0.1f,
                size = Random.nextFloat() * 8f + 4f,
                color = listOf(
                    Color(0xFFFFD700),
                    Color(0xFF2563EB),
                    Color(0xFF13EF92),
                    Color(0xFFF04C4C),
                    Color(0xFFFEE440)
                ).random(),
                speedY = Random.nextFloat() * 0.002f + 0.001f,
                rotation = Random.nextFloat() * 360f
            )
        })
    }

    LaunchedEffect(Unit) {
        while (true) {
            delay(16) // ~60 FPS
            particles = particles.map { p ->
                p.copy(
                    y = if (p.y > 1.1f) -0.1f else p.y + p.speedY,
                    rotation = p.rotation + 2f
                )
            }
        }
    }

    Canvas(modifier = Modifier.fillMaxSize()) {
        particles.forEach { particle ->
            val centerX = size.width * particle.x
            val centerY = size.height * particle.y

            drawCircle(
                color = particle.color,
                radius = particle.size,
                center = androidx.compose.ui.geometry.Offset(centerX, centerY)
            )
        }
    }
}

private data class ConfettiParticle(
    val x: Float,
    val y: Float,
    val size: Float,
    val color: Color,
    val speedY: Float,
    val rotation: Float
)

private fun getBadgeIcon(iconName: String): ImageVector {
    return when (iconName) {
        "EmojiEvents" -> Icons.Filled.EmojiEvents
        "FitnessCenter" -> Icons.Filled.FitnessCenter
        "LocalFireDepartment" -> Icons.Filled.LocalFireDepartment
        "Star" -> Icons.Filled.Star
        "Person" -> Icons.Filled.Person
        "Group" -> Icons.Filled.Group
        "WbSunny" -> Icons.Filled.WbSunny
        "NightsStay" -> Icons.Filled.NightsStay
        "CalendarToday" -> Icons.Filled.CalendarToday
        else -> Icons.Filled.EmojiEvents
    }
}

